UPDATE words SET example_en_2 = 'It was a sunny afternoon, so we decided to have a picnic in the park.', example_ko_2 = '화창한 오후여서 공원에서 소풍을 하기로 했어요.', example_en_3 = 'The sunny weather made everyone feel cheerful and energetic.', example_ko_3 = '화창한 날씨 덕분에 모두가 기분 좋고 활기차게 느꼈어요.', example_en_4 = 'We went to the beach on a sunny day last weekend.', example_ko_4 = '지난 주말에 화창한 날 해변에 갔어요.', example_en_5 = 'It is sunny outside, so you don''t need a jacket today.', example_ko_5 = '밖이 화창하니까 오늘은 재킷이 필요 없어요.' WHERE id = 'w_weather_A1_01';
UPDATE words SET example_en_2 = 'It was so rainy that the streets were completely flooded.', example_ko_2 = '비가 너무 많이 와서 거리가 완전히 잠겼어요.', example_en_3 = 'On rainy days, I like to stay inside and read a book.', example_ko_3 = '비 오는 날에는 집 안에서 책을 읽는 것을 좋아해요.', example_en_4 = 'The rainy season usually starts in June here.', example_ko_4 = '이곳에서 우기는 보통 6월에 시작해요.', example_en_5 = 'Take your raincoat because it looks rainy outside.', example_ko_5 = '밖이 비 올 것 같으니까 우비를 챙기세요.' WHERE id = 'w_weather_A1_02';
UPDATE words SET example_en_2 = 'It is so hot today that I do not want to go outside at all.', example_ko_2 = '오늘 너무 더워서 밖에 나가고 싶지 않아요.', example_en_3 = 'The soup is still hot, so please be careful when you drink it.', example_ko_3 = '수프가 아직 뜨거우니까 마실 때 조심하세요.', example_en_4 = 'We needed cold drinks because the weather was so hot.', example_ko_4 = '날씨가 너무 더워서 차가운 음료가 필요했어요.', example_en_5 = 'August is the hottest month of the year in Korea.', example_ko_5 = '8월은 한국에서 일 년 중 가장 더운 달이에요.' WHERE id = 'w_weather_A1_03';
UPDATE words SET example_en_2 = 'It is very cold outside, so please wear a warm coat.', example_ko_2 = '밖이 매우 추우니까 따뜻한 코트를 입으세요.', example_en_3 = 'My hands were cold because I forgot my gloves.', example_ko_3 = '장갑을 잊고 와서 손이 차가웠어요.', example_en_4 = 'The cold weather makes me want to drink hot chocolate.', example_ko_4 = '추운 날씨에는 핫초코가 마시고 싶어져요.', example_en_5 = 'January is the coldest month of the year in most of Korea.', example_ko_5 = '1월은 한국 대부분 지역에서 가장 추운 달이에요.' WHERE id = 'w_weather_A1_04';
UPDATE words SET example_en_2 = 'It was so windy that my umbrella turned inside out.', example_ko_2 = '바람이 너무 강해서 우산이 뒤집어졌어요.', example_en_3 = 'The windy weather made it hard to walk along the seafront.', example_ko_3 = '바람이 강해서 해안가를 걷기가 힘들었어요.', example_en_4 = 'Hold onto your hat — it is really windy today!', example_ko_4 = '오늘 바람이 정말 강하니까 모자를 꽉 잡으세요!', example_en_5 = 'Windy conditions are expected throughout the afternoon.', example_ko_5 = '오후 내내 강한 바람이 예상돼요.' WHERE id = 'w_weather_A1_05';
UPDATE words SET example_en_2 = 'It was cloudy all day, but it did not rain.', example_ko_2 = '하루 종일 흐렸지만 비는 오지 않았어요.', example_en_3 = 'The sky became cloudy just as we arrived at the beach.', example_ko_3 = '우리가 해변에 도착하자마자 하늘이 흐려졌어요.', example_en_4 = 'A cloudy day is actually perfect for hiking because it is not too hot.', example_ko_4 = '흐린 날은 너무 덥지 않아서 하이킹하기에 오히려 좋아요.', example_en_5 = 'The forecast says it will be cloudy with a chance of rain tomorrow.', example_ko_5 = '내일은 흐리고 비가 올 수도 있다고 예보가 말해요.' WHERE id = 'w_weather_A1_06';
UPDATE words SET example_en_2 = 'The children were excited to play in the snow for the first time.', example_ko_2 = '아이들은 처음으로 눈 속에서 놀 수 있어서 신나 했어요.', example_en_3 = 'Heavy snow blocked the roads and schools were closed.', example_ko_3 = '폭설로 도로가 막혀서 학교가 문을 닫았어요.', example_en_4 = 'I love watching snow fall quietly outside my window.', example_ko_4 = '창문 밖으로 눈이 조용히 내리는 것을 보는 것을 좋아해요.', example_en_5 = 'The mountains are covered in snow from November to March.', example_ko_5 = '11월부터 3월까지 산은 눈으로 덮여 있어요.' WHERE id = 'w_weather_A1_07';
UPDATE words SET example_en_2 = 'Spring days are warm and perfect for a walk in the park.', example_ko_2 = '봄날은 따뜻해서 공원 산책하기에 딱 좋아요.', example_en_3 = 'It is warm enough today to go outside without a jacket.', example_ko_3 = '오늘은 재킷 없이 밖에 나가도 될 만큼 따뜻해요.', example_en_4 = 'The warm breeze made the evening very pleasant.', example_ko_4 = '따뜻한 바람 덕분에 저녁이 아주 기분 좋았어요.', example_en_5 = 'I prefer warm weather to cold weather any day.', example_ko_5 = '저는 언제나 추운 날씨보다 따뜻한 날씨를 더 좋아해요.' WHERE id = 'w_weather_A1_08';
UPDATE words SET example_en_2 = 'October mornings are cool and refreshing here.', example_ko_2 = '이곳의 10월 아침은 서늘하고 상쾌해요.', example_en_3 = 'A cool breeze came in through the open window.', example_ko_3 = '열린 창문으로 시원한 바람이 들어왔어요.', example_en_4 = 'The evening air was cool after the hot summer day.', example_ko_4 = '더운 여름날 이후 저녁 공기가 서늘했어요.', example_en_5 = 'It is quite cool today, so a light cardigan should be enough.', example_ko_5 = '오늘은 꽤 서늘하니까 가벼운 가디건 정도면 충분할 거예요.' WHERE id = 'w_weather_A1_09';
UPDATE words SET example_en_2 = 'The weather app on my phone is very useful every morning.', example_ko_2 = '매일 아침 핸드폰의 날씨 앱이 정말 유용해요.', example_en_3 = 'The weather here changes very quickly, so always be prepared.', example_ko_3 = '이곳의 날씨는 매우 빠르게 변하니까 항상 대비하세요.', example_en_4 = 'What is the weather like where you live?', example_ko_4 = '사시는 곳의 날씨는 어떤가요?', example_en_5 = 'The weather forecast for the weekend looks really good.', example_ko_5 = '주말 날씨 예보가 정말 좋아 보여요.' WHERE id = 'w_weather_A1_10';
UPDATE words SET example_en_2 = 'The rain came down so hard that we had to stop walking.', example_ko_2 = '비가 너무 세게 내려서 걷는 것을 멈춰야 했어요.', example_en_3 = 'A little rain is good for the garden, actually.', example_ko_3 = '사실 약간의 비는 정원에 좋아요.', example_en_4 = 'The rain has stopped, so we can go outside now.', example_ko_4 = '비가 그쳤으니까 이제 밖에 나가도 돼요.', example_en_5 = 'We could hear the rain on the roof all night long.', example_ko_5 = '밤새 지붕 위로 빗소리가 들렸어요.' WHERE id = 'w_weather_A1_11';
UPDATE words SET example_en_2 = 'The sun was so bright that I had to wear sunglasses.', example_ko_2 = '햇빛이 너무 밝아서 선글라스를 써야 했어요.', example_en_3 = 'The sun sets later in the evening during summer.', example_ko_3 = '여름에는 해가 저녁 늦게 져요.', example_en_4 = 'Do not look directly at the sun — it can damage your eyes.', example_ko_4 = '태양을 직접 보지 마세요 — 눈에 손상을 줄 수 있어요.', example_en_5 = 'The sun came out from behind the clouds and warmed everything up.', example_ko_5 = '구름 뒤에서 해가 나와서 모든 것이 따뜻해졌어요.' WHERE id = 'w_weather_A1_12';
UPDATE words SET example_en_2 = 'The wind knocked over the flower pots on the balcony.', example_ko_2 = '바람이 발코니의 화분들을 쓰러뜨렸어요.', example_en_3 = 'A strong wind is blowing from the north today.', example_ko_3 = '오늘은 북쪽에서 강한 바람이 불고 있어요.', example_en_4 = 'The wind made the temperature feel much colder than it was.', example_ko_4 = '바람 때문에 실제보다 훨씬 춥게 느껴졌어요.', example_en_5 = 'We could feel a gentle wind coming off the sea.', example_ko_5 = '바다에서 불어오는 부드러운 바람을 느낄 수 있었어요.' WHERE id = 'w_weather_A1_13';
UPDATE words SET example_en_2 = 'There was not a single cloud in the sky all day.', example_ko_2 = '하루 종일 하늘에 구름 한 점 없었어요.', example_en_3 = 'Dark clouds gathered quickly before the storm hit.', example_ko_3 = '폭풍이 오기 전에 먹구름이 빠르게 모였어요.', example_en_4 = 'The white clouds looked beautiful against the blue sky.', example_ko_4 = '파란 하늘을 배경으로 흰 구름이 아름다워 보였어요.', example_en_5 = 'That cloud looks like a rabbit — can you see it?', example_ko_5 = '저 구름이 토끼처럼 생겼어요 — 보이세요?' WHERE id = 'w_weather_A1_14';
UPDATE words SET example_en_2 = 'The ice on the road made driving very dangerous this morning.', example_ko_2 = '오늘 아침 도로의 얼음 때문에 운전이 매우 위험했어요.', example_en_3 = 'Please add some ice to my drink — it is too warm.', example_ko_3 = '음료에 얼음을 좀 넣어 주세요 — 너무 따뜻해요.', example_en_4 = 'The ice on the lake was thick enough to walk on.', example_ko_4 = '호수의 얼음이 걸어 다닐 수 있을 만큼 두꺼웠어요.', example_en_5 = 'The children slipped on the ice in front of the school.', example_ko_5 = '아이들이 학교 앞 얼음 위에서 미끄러졌어요.' WHERE id = 'w_weather_A1_15';
UPDATE words SET example_en_2 = 'My shoes got completely wet after walking through the puddles.', example_ko_2 = '웅덩이를 걸어서 신발이 완전히 젖었어요.', example_en_3 = 'The grass was still wet from the rain this morning.', example_ko_3 = '오늘 아침 비 때문에 풀이 아직 젖어 있었어요.', example_en_4 = 'Please wipe your wet shoes before coming inside.', example_ko_4 = '안으로 들어오기 전에 젖은 신발을 닦아 주세요.', example_en_5 = 'The wet road reflected the streetlights beautifully at night.', example_ko_5 = '밤에 젖은 도로가 가로등 빛을 아름답게 반사했어요.' WHERE id = 'w_weather_A1_16';
UPDATE words SET example_en_2 = 'The desert climate is extremely dry with very little rain.', example_ko_2 = '사막 기후는 비가 거의 없어서 매우 건조해요.', example_en_3 = 'My skin gets very dry in winter, so I use a lot of moisturizer.', example_ko_3 = '겨울에는 피부가 매우 건조해져서 보습제를 많이 사용해요.', example_en_4 = 'Store the biscuits in a dry place so they stay crisp.', example_ko_4 = '비스킷이 바삭하게 유지되도록 건조한 곳에 보관하세요.', example_en_5 = 'The dry season here lasts from October to April.', example_ko_5 = '이곳의 건기는 10월부터 4월까지예요.' WHERE id = 'w_weather_A1_17';
UPDATE words SET example_en_2 = 'A tropical storm is a powerful storm that forms over warm ocean water.', example_ko_2 = '열대 폭풍은 따뜻한 바닷물 위에서 형성되는 강력한 폭풍이에요.', example_en_3 = 'The storm last night damaged many trees and power lines.', example_ko_3 = '어젯밤 폭풍이 많은 나무와 전선을 손상시켰어요.', example_en_4 = 'We stayed inside during the storm because it was too dangerous outside.', example_ko_4 = '폭풍 동안 밖이 너무 위험해서 안에 있었어요.', example_en_5 = 'A storm is approaching, so please secure any loose items outside.', example_ko_5 = '폭풍이 다가오고 있으니까 밖에 있는 느슨한 물건들을 고정하세요.' WHERE id = 'w_weather_A1_18';
UPDATE words SET example_en_2 = 'I always keep an umbrella in my bag just in case it rains.', example_ko_2 = '비가 올 경우를 대비해서 항상 가방에 우산을 챙겨요.', example_en_3 = 'Can I borrow your umbrella? I forgot mine today.', example_ko_3 = '우산을 빌릴 수 있을까요? 오늘 제 것을 잊어버렸어요.', example_en_4 = 'The strong wind broke my umbrella on the way home.', example_ko_4 = '집에 오는 길에 강한 바람에 우산이 부러졌어요.', example_en_5 = 'You should buy a bigger umbrella if you want to stay dry in heavy rain.', example_ko_5 = '폭우에도 젖지 않으려면 더 큰 우산을 사세요.' WHERE id = 'w_weather_A1_19';
UPDATE words SET example_en_2 = 'I bought a new winter coat because my old one was too thin.', example_ko_2 = '기존 코트가 너무 얇아서 새 겨울 코트를 샀어요.', example_en_3 = 'Put on your coat before you go outside — it is freezing.', example_ko_3 = '밖에 나가기 전에 코트를 입으세요 — 얼어붙을 정도예요.', example_en_4 = 'That coat looks really warm and stylish on you.', example_ko_4 = '그 코트가 따뜻하고 스타일리쉬해 보여요.', example_en_5 = 'I hung my wet coat by the radiator to dry it quickly.', example_ko_5 = '젖은 코트를 빨리 말리려고 라디에이터 옆에 걸었어요.' WHERE id = 'w_weather_A1_20';
UPDATE words SET example_en_2 = 'Each season brings its own beauty and its own weather patterns.', example_ko_2 = '각 계절은 저마다의 아름다움과 날씨 패턴을 가져와요.', example_en_3 = 'My favourite season is autumn because of the colourful leaves.', example_ko_3 = '알록달록한 단풍 때문에 가을이 가장 좋아하는 계절이에요.', example_en_4 = 'Korea has four distinct seasons with very different temperatures.', example_ko_4 = '한국은 기온이 매우 다른 뚜렷한 사계절이 있어요.', example_en_5 = 'Which season do you enjoy the most and why?', example_ko_5 = '어떤 계절을 가장 좋아하세요, 그리고 이유는 뭔가요?' WHERE id = 'w_weather_A1_21';
UPDATE words SET example_en_2 = 'Spring is the best time to visit the cherry blossom parks.', example_ko_2 = '봄은 벚꽃 공원을 방문하기에 가장 좋은 시기예요.', example_en_3 = 'In spring, the days get longer and the weather gets warmer.', example_ko_3 = '봄이 되면 낮이 길어지고 날씨가 따뜻해져요.', example_en_4 = 'Spring allergies can be difficult if you are sensitive to pollen.', example_ko_4 = '꽃가루에 민감하면 봄 알레르기가 힘들 수 있어요.', example_en_5 = 'We planted flowers in our garden at the start of spring.', example_ko_5 = '봄이 시작될 때 정원에 꽃을 심었어요.' WHERE id = 'w_weather_A1_22';
UPDATE words SET example_en_2 = 'Summer is the perfect time to go swimming at the beach.', example_ko_2 = '여름은 해변에서 수영하기에 완벽한 시기예요.', example_en_3 = 'The summer heat in Seoul can be very intense in August.', example_ko_3 = '서울의 여름 더위는 8월에 매우 강렬해요.', example_en_4 = 'I spent last summer travelling around Europe by train.', example_ko_4 = '지난여름에는 기차로 유럽을 여행했어요.', example_en_5 = 'Summer evenings are long and warm, which I really enjoy.', example_ko_5 = '여름 저녁은 길고 따뜻해서 정말 좋아해요.' WHERE id = 'w_weather_A1_23';
UPDATE words SET example_en_2 = 'Winter mornings are very cold and dark here in Korea.', example_ko_2 = '한국의 겨울 아침은 매우 춥고 어두워요.', example_en_3 = 'I like winter because of Christmas and the festive atmosphere.', example_ko_3 = '크리스마스와 축제 분위기 때문에 겨울을 좋아해요.', example_en_4 = 'In winter, I always make sure to wear warm layers.', example_ko_4 = '겨울에는 항상 따뜻하게 겹쳐 입어요.', example_en_5 = 'The ski resort is only open during the winter months.', example_ko_5 = '스키 리조트는 겨울철에만 개장해요.' WHERE id = 'w_weather_A1_24';
UPDATE words SET example_en_2 = 'It is very cold outside, so please wear a warm hat.', example_ko_2 = '밖이 매우 추우니까 따뜻한 모자를 쓰세요.', example_en_3 = 'The children want to play outside but it is raining.', example_ko_3 = '아이들이 밖에서 놀고 싶어 하지만 비가 와요.', example_en_4 = 'Let''s go outside and enjoy the fresh air after lunch.', example_ko_4 = '점심 후에 밖에 나가서 신선한 공기를 즐겨요.', example_en_5 = 'It was so cold outside that the water in the pipes froze.', example_ko_5 = '밖이 너무 추워서 파이프 안의 물이 얼었어요.' WHERE id = 'w_weather_A1_25';
UPDATE words SET example_en_2 = 'The sky turned orange and pink at sunset — it was beautiful.', example_ko_2 = '해가 질 때 하늘이 주황색과 분홍색으로 물들었어요 — 아름다웠어요.', example_en_3 = 'Look at the blue sky today — there is not a cloud in sight.', example_ko_3 = '오늘 파란 하늘을 보세요 — 구름 한 점 없어요.', example_en_4 = 'The dark sky before the storm was quite frightening.', example_ko_4 = '폭풍 전의 어두운 하늘이 꽤 무서웠어요.', example_en_5 = 'We lay on the grass and looked up at the sky for a long time.', example_ko_5 = '잔디에 누워서 오랫동안 하늘을 바라봤어요.' WHERE id = 'w_weather_A1_26';
UPDATE words SET example_en_2 = 'The temperature dropped to minus ten degrees last night.', example_ko_2 = '어젯밤 기온이 영하 10도까지 떨어졌어요.', example_en_3 = 'Please check the temperature before deciding what to wear today.', example_ko_3 = '오늘 뭘 입을지 결정하기 전에 기온을 확인하세요.', example_en_4 = 'Body temperature is normally around 36 to 37 degrees Celsius.', example_ko_4 = '체온은 보통 섭씨 36도에서 37도 정도예요.', example_en_5 = 'The temperature in the desert can reach 50 degrees during summer.', example_ko_5 = '사막의 여름 기온은 50도까지 올라갈 수 있어요.' WHERE id = 'w_weather_A1_27';
UPDATE words SET example_en_2 = 'There was thick fog on the motorway and many accidents happened.', example_ko_2 = '고속도로에 짙은 안개가 껴서 사고가 많이 났어요.', example_en_3 = 'The fog lifted by midday and the sun came out.', example_ko_3 = '낮이 되자 안개가 걷히고 해가 나왔어요.', example_en_4 = 'Flying can be delayed when there is heavy fog at the airport.', example_ko_4 = '공항에 짙은 안개가 끼면 비행기가 지연될 수 있어요.', example_en_5 = 'The fog made the city look mysterious and quiet early in the morning.', example_ko_5 = '이른 아침 안개가 도시를 신비롭고 조용하게 보이게 했어요.' WHERE id = 'w_weather_A1_28';
UPDATE words SET example_en_2 = 'The sunshine through the trees made beautiful patterns on the ground.', example_ko_2 = '나무 사이로 비치는 햇빛이 땅 위에 아름다운 무늬를 만들었어요.', example_en_3 = 'A little bit of sunshine can really brighten your mood.', example_ko_3 = '약간의 햇빛만으로도 기분이 정말 좋아질 수 있어요.', example_en_4 = 'We finally got some sunshine after a week of rain.', example_ko_4 = '일주일간의 비 끝에 드디어 햇빛이 났어요.', example_en_5 = 'The forecast promises plenty of sunshine this weekend.', example_ko_5 = '이번 주말에는 햇빛이 충분히 날 것이라고 예보가 말해요.' WHERE id = 'w_weather_A1_29';
UPDATE words SET example_en_2 = 'A beautiful rainbow appeared right after the rain stopped.', example_ko_2 = '비가 그치자마자 아름다운 무지개가 나타났어요.', example_en_3 = 'The children ran outside to see the rainbow in the sky.', example_ko_3 = '아이들이 하늘의 무지개를 보려고 밖으로 뛰어나갔어요.', example_en_4 = 'A rainbow has seven colours: red, orange, yellow, green, blue, indigo, and violet.', example_ko_4 = '무지개는 빨강, 주황, 노랑, 초록, 파랑, 남색, 보라의 7가지 색깔이 있어요.', example_en_5 = 'It is rare to see a double rainbow — have you ever seen one?', example_ko_5 = '쌍무지개를 보는 것은 드문 일이에요 — 본 적이 있으세요?' WHERE id = 'w_weather_A1_30';
UPDATE words SET example_en_2 = 'Hail damaged the roof of our car during the storm.', example_ko_2 = '폭풍 동안 우박이 차 지붕을 손상시켰어요.', example_en_3 = 'The hail stones were as large as golf balls — it was incredible.', example_ko_3 = '우박 알갱이가 골프공만큼 컸어요 — 믿기 어려울 정도였어요.', example_en_4 = 'We quickly ran inside when the hail started falling.', example_ko_4 = '우박이 내리기 시작하자 우리는 재빨리 안으로 뛰어 들어갔어요.', example_en_5 = 'Hail can cause serious damage to crops and buildings.', example_ko_5 = '우박은 농작물과 건물에 심각한 피해를 줄 수 있어요.' WHERE id = 'w_weather_A1_31';
UPDATE words SET example_en_2 = 'The thunder was so loud that it woke up the whole neighbourhood.', example_ko_2 = '천둥 소리가 너무 커서 온 동네가 잠에서 깼어요.', example_en_3 = 'I always count the seconds between thunder and lightning to estimate the distance.', example_ko_3 = '저는 항상 천둥과 번개 사이의 초를 세어서 거리를 추정해요.', example_en_4 = 'The thunder rolled through the valley for several seconds.', example_ko_4 = '천둥이 몇 초 동안 계곡을 가로질러 울렸어요.', example_en_5 = 'Our dog hides under the bed whenever it hears thunder.', example_ko_5 = '우리 개는 천둥 소리를 들을 때마다 침대 밑에 숨어요.' WHERE id = 'w_weather_A1_32';
UPDATE words SET example_en_2 = 'A bolt of lightning struck the tall tree in our garden.', example_ko_2 = '번개가 우리 정원의 키 큰 나무를 쳤어요.', example_en_3 = 'Never stand under a tree during a lightning storm.', example_ko_3 = '번개가 치는 동안 절대 나무 아래 서 있지 마세요.', example_en_4 = 'The lightning lit up the whole sky for a split second.', example_ko_4 = '번개가 순간적으로 하늘 전체를 밝혔어요.', example_en_5 = 'Lightning can travel at speeds of up to 220,000 kilometres per hour.', example_ko_5 = '번개는 시속 22만 킬로미터의 속도로 이동할 수 있어요.' WHERE id = 'w_weather_A1_33';
