UPDATE words SET example_en_2 = 'The leaves change colour beautifully in autumn.', example_ko_2 = '가을에는 나뭇잎이 아름답게 색이 변해요.', example_en_3 = 'Autumn is a great time for hiking because the air is crisp and cool.', example_ko_3 = '공기가 상쾌하고 서늘해서 가을은 하이킹하기 좋은 시기예요.', example_en_4 = 'I love the smell of autumn — the fallen leaves and cool air.', example_ko_4 = '떨어진 낙엽과 서늘한 공기 같은 가을 냄새를 좋아해요.', example_en_5 = 'Autumn in Korea is short but incredibly beautiful.', example_ko_5 = '한국의 가을은 짧지만 믿을 수 없을 만큼 아름다워요.' WHERE id = 'w_weather_A1_35';
UPDATE words SET example_en_2 = 'The weather forecast was wrong again — it said sunny but it rained all day.', example_ko_2 = '날씨 예보가 또 틀렸어요 — 맑다고 했는데 하루 종일 비가 왔어요.', example_en_3 = 'I always check the forecast before planning outdoor activities.', example_ko_3 = '야외 활동을 계획하기 전에 항상 예보를 확인해요.', example_en_4 = 'The five-day forecast shows rain for most of next week.', example_ko_4 = '5일 예보를 보니 다음 주 대부분 비가 올 것 같아요.', example_en_5 = 'According to the forecast, tomorrow will be the hottest day of the year.', example_ko_5 = '예보에 따르면 내일이 올해 가장 더운 날이 될 거예요.' WHERE id = 'w_weather_A2_01';
UPDATE words SET example_en_2 = 'The temperature outside has been above 35 degrees all week.', example_ko_2 = '밖의 기온이 일주일 내내 35도 이상이었어요.', example_en_3 = 'Water boils at a temperature of 100 degrees Celsius.', example_ko_3 = '물은 섭씨 100도의 온도에서 끓어요.', example_en_4 = 'The temperature in the classroom was too cold to concentrate.', example_ko_4 = '교실 온도가 너무 차가워서 집중하기 어려웠어요.', example_en_5 = 'Please set the thermostat to a comfortable temperature for everyone.', example_ko_5 = '모두에게 편안한 온도로 온도 조절기를 설정해 주세요.' WHERE id = 'w_weather_A2_02';
UPDATE words SET example_en_2 = 'The air is so humid that my hair goes frizzy every morning.', example_ko_2 = '공기가 너무 습해서 매일 아침 머리카락이 부스스해져요.', example_en_3 = 'It feels even hotter when the weather is humid.', example_ko_3 = '날씨가 습할 때는 더 덥게 느껴져요.', example_en_4 = 'The humid climate near the coast can be uncomfortable in summer.', example_ko_4 = '해안 근처의 습한 기후는 여름에 불편할 수 있어요.', example_en_5 = 'I prefer dry heat over humid heat any day.', example_ko_5 = '저는 언제나 습한 더위보다 건조한 더위를 더 좋아해요.' WHERE id = 'w_weather_A2_03';
UPDATE words SET example_en_2 = 'The thunder shook the windows and scared the children.', example_ko_2 = '천둥이 창문을 흔들고 아이들을 놀라게 했어요.', example_en_3 = 'I could hear thunder in the distance as the storm approached.', example_ko_3 = '폭풍이 다가오면서 멀리서 천둥 소리가 들렸어요.', example_en_4 = 'There was a loud clap of thunder just as we reached the car.', example_ko_4 = '우리가 차에 도착하자마자 크고 요란한 천둥 소리가 났어요.', example_en_5 = 'Thunder without lightning is actually very rare.', example_ko_5 = '번개 없는 천둥은 사실 매우 드물어요.' WHERE id = 'w_weather_A2_04';
UPDATE words SET example_en_2 = 'We watched the lightning flash over the sea from the safety of the hotel.', example_ko_2 = '호텔 안의 안전한 곳에서 바다 위로 번개가 치는 것을 지켜봤어요.', example_en_3 = 'Lightning struck the power lines and caused a blackout in our area.', example_ko_3 = '번개가 전선을 치면서 우리 지역에 정전이 발생했어요.', example_en_4 = 'Stay indoors and avoid using electrical appliances during a lightning storm.', example_ko_4 = '번개가 치는 동안에는 실내에 있고 전기 기구 사용을 피하세요.', example_en_5 = 'The lightning made the night sky look like daytime for a brief moment.', example_ko_5 = '번개가 잠깐 동안 밤하늘을 낮처럼 밝게 만들었어요.' WHERE id = 'w_weather_A2_05';
UPDATE words SET example_en_2 = 'We drove slowly because of the thick fog on the road.', example_ko_2 = '도로의 짙은 안개 때문에 천천히 운전했어요.', example_en_3 = 'The fog horn sounded all night to warn the ships.', example_ko_3 = '배들에게 경고하기 위해 밤새 안개 경적이 울렸어요.', example_en_4 = 'The mountain peak disappeared into the fog and we could not see it at all.', example_ko_4 = '산 정상이 안개 속으로 사라져서 전혀 볼 수 없었어요.', example_en_5 = 'Fog lights on your car are essential when visibility is low.', example_ko_5 = '시야가 낮을 때는 차의 안개등이 필수예요.' WHERE id = 'w_weather_A2_06';
UPDATE words SET example_en_2 = 'The frost on the grass melted as soon as the sun came out.', example_ko_2 = '해가 나오자마자 잔디 위의 서리가 녹았어요.', example_en_3 = 'The first frost of the season appeared on the car windscreens this morning.', example_ko_3 = '오늘 아침 계절의 첫 서리가 자동차 앞유리에 맺혔어요.', example_en_4 = 'Farmers are worried about frost damaging their crops tonight.', example_ko_4 = '농부들은 오늘 밤 서리가 농작물에 피해를 줄까 봐 걱정해요.', example_en_5 = 'There was a heavy frost overnight and the garden looked magical.', example_ko_5 = '밤새 서리가 심하게 내려서 정원이 마법 같아 보였어요.' WHERE id = 'w_weather_A2_07';
UPDATE words SET example_en_2 = 'A light drizzle began just as I stepped outside without an umbrella.', example_ko_2 = '우산 없이 밖에 나서자마자 가랑비가 내리기 시작했어요.', example_en_3 = 'The drizzle was not heavy enough to ruin our picnic completely.', example_ko_3 = '가랑비가 심하지 않아서 소풍을 완전히 망치지는 않았어요.', example_en_4 = 'A gentle drizzle fell throughout the afternoon, keeping everything damp.', example_ko_4 = '오후 내내 가랑비가 내려서 모든 것이 축축하게 유지됐어요.', example_en_5 = 'It is only a drizzle, so you will be fine without a raincoat.', example_ko_5 = '가랑비일 뿐이니까 우비 없이도 괜찮을 거예요.' WHERE id = 'w_weather_A2_08';
UPDATE words SET example_en_2 = 'A cool breeze from the sea made the hot afternoon much more bearable.', example_ko_2 = '바다에서 불어오는 시원한 바람 덕분에 더운 오후가 훨씬 견딜 만해졌어요.', example_en_3 = 'A gentle breeze rustled the leaves in the garden.', example_ko_3 = '산들바람이 정원의 나뭇잎을 살랑살랑 흔들었어요.', example_en_4 = 'Open the window to let in a bit of breeze — it is so stuffy in here.', example_ko_4 = '바람이 좀 들어오게 창문을 열어요 — 여기 너무 답답해요.', example_en_5 = 'The evening breeze made it a lovely night to sit on the terrace.', example_ko_5 = '저녁 바람 덕분에 테라스에 앉기에 멋진 밤이었어요.' WHERE id = 'w_weather_A2_09';
UPDATE words SET example_en_2 = 'We had a short shower in the morning but the afternoon was clear.', example_ko_2 = '오전에 소나기가 잠깐 왔지만 오후에는 맑았어요.', example_en_3 = 'A heavy shower caught us off guard without our umbrellas.', example_ko_3 = '갑작스러운 폭우에 우산 없이 당했어요.', example_en_4 = 'The forecast mentioned scattered showers throughout the day.', example_ko_4 = '예보에서 하루 종일 간헐적인 소나기가 올 거라고 했어요.', example_en_5 = 'I got caught in a shower on the way back from the market.', example_ko_5 = '시장에서 돌아오는 길에 소나기를 맞았어요.' WHERE id = 'w_weather_A2_10';
UPDATE words SET example_en_2 = 'The sky was completely overcast, making the day feel very gloomy.', example_ko_2 = '하늘이 완전히 흐려서 하루가 매우 우울하게 느껴졌어요.', example_en_3 = 'Overcast conditions are actually better for photography because the light is softer.', example_ko_3 = '흐린 날씨에는 빛이 더 부드러워서 사진 찍기에 오히려 좋아요.', example_en_4 = 'The weather has been overcast for almost a week now.', example_ko_4 = '날씨가 거의 일주일 동안 계속 흐렸어요.', example_en_5 = 'I find overcast mornings quite peaceful and calm.', example_ko_5 = '흐린 아침이 꽤 평화롭고 고요하게 느껴져요.' WHERE id = 'w_weather_A2_11';
UPDATE words SET example_en_2 = 'The blizzard closed all major roads and airports in the region.', example_ko_2 = '눈보라가 지역 내 모든 주요 도로와 공항을 폐쇄시켰어요.', example_en_3 = 'We were stuck at home for three days during the blizzard.', example_ko_3 = '눈보라 동안 3일 동안 집에 갇혀 있었어요.', example_en_4 = 'The forecast is warning of a severe blizzard tonight.', example_ko_4 = '예보에서 오늘 밤 심한 눈보라를 경고하고 있어요.', example_en_5 = 'The blizzard made visibility nearly zero on the mountain roads.', example_ko_5 = '눈보라가 산길의 시야를 거의 제로에 가깝게 만들었어요.' WHERE id = 'w_weather_A2_12';
UPDATE words SET example_en_2 = 'People were advised to stay indoors during the heatwave.', example_ko_2 = '폭염 동안 사람들은 실내에 있으라는 권고를 받았어요.', example_en_3 = 'The heatwave caused power cuts as air conditioner use surged.', example_ko_3 = '에어컨 사용이 급증하면서 폭염이 정전을 유발했어요.', example_en_4 = 'The summer heatwave set a new temperature record in Seoul.', example_ko_4 = '여름 폭염이 서울에서 새로운 기온 기록을 세웠어요.', example_en_5 = 'During the heatwave, it is important to drink plenty of water.', example_ko_5 = '폭염 동안에는 물을 충분히 마시는 것이 중요해요.' WHERE id = 'w_weather_A2_13';
UPDATE words SET example_en_2 = 'The road was slippery after the overnight frost, so drive carefully.', example_ko_2 = '밤새 서리가 내려 도로가 미끄러우니까 조심해서 운전하세요.', example_en_3 = 'The wet tiles in the shower can be very slippery — be careful.', example_ko_3 = '샤워실의 젖은 타일은 매우 미끄러울 수 있으니 조심하세요.', example_en_4 = 'The slippery path through the park caused several falls this morning.', example_ko_4 = '공원의 미끄러운 길 때문에 오늘 아침 몇 건의 낙상 사고가 났어요.', example_en_5 = 'Wear shoes with good grip in wet or slippery conditions.', example_ko_5 = '젖거나 미끄러운 환경에서는 그립이 좋은 신발을 신으세요.' WHERE id = 'w_weather_A2_14';
UPDATE words SET example_en_2 = 'The humid summer air made sleeping very difficult without air conditioning.', example_ko_2 = '에어컨 없이는 습한 여름 공기 때문에 자기가 매우 어려웠어요.', example_en_3 = 'My clothes feel damp because of how humid it is today.', example_ko_3 = '오늘 너무 습해서 옷이 축축하게 느껴져요.', example_en_4 = 'Humid weather is common in coastal cities during summer.', example_ko_4 = '여름 동안 해안 도시에서는 습한 날씨가 흔해요.', example_en_5 = 'It is incredibly humid today — I am sweating just standing still.', example_ko_5 = '오늘 정말 습해요 — 가만히 서 있기만 해도 땀이 나요.' WHERE id = 'w_weather_A2_15';
UPDATE words SET example_en_2 = 'It is a bit chilly this morning — you might want a scarf.', example_ko_2 = '오늘 아침 약간 쌀쌀하니까 스카프를 두르는 게 좋을 것 같아요.', example_en_3 = 'The chilly autumn breeze signals that winter is on its way.', example_ko_3 = '쌀쌀한 가을 바람이 겨울이 다가오고 있다는 신호예요.', example_en_4 = 'I always feel chilly in air-conditioned offices during summer.', example_ko_4 = '여름에는 에어컨이 켜진 사무실에서 항상 쌀쌀하게 느껴져요.', example_en_5 = 'The chilly evening air is perfect for a walk along the river.', example_ko_5 = '쌀쌀한 저녁 공기가 강변 산책에 딱 좋아요.' WHERE id = 'w_weather_A2_16';
UPDATE words SET example_en_2 = 'Spring in this region tends to be mild with pleasant temperatures.', example_ko_2 = '이 지역의 봄은 기온이 쾌적하고 온화한 편이에요.', example_en_3 = 'The weather was mild enough to eat lunch outside at the café.', example_ko_3 = '카페 밖에서 점심을 먹을 만큼 날씨가 온화했어요.', example_en_4 = 'I enjoy mild winters because I do not like extreme cold.', example_ko_4 = '극한의 추위를 싫어해서 온화한 겨울을 좋아해요.', example_en_5 = 'The doctor recommended a mild climate for his recovery.', example_ko_5 = '의사는 그의 회복을 위해 온화한 기후를 권했어요.' WHERE id = 'w_weather_A2_17';
UPDATE words SET example_en_2 = 'It started to pour just as the outdoor concert began.', example_ko_2 = '야외 콘서트가 시작되자마자 비가 쏟아지기 시작했어요.', example_en_3 = 'We had to cancel the barbecue because it was pouring outside.', example_ko_3 = '밖에 비가 쏟아지고 있어서 바비큐를 취소해야 했어요.', example_en_4 = 'It is pouring with rain, so we will wait inside a bit longer.', example_ko_4 = '비가 쏟아지고 있으니까 좀 더 안에서 기다릴게요.', example_en_5 = 'The rain began to pour heavily around three in the afternoon.', example_ko_5 = '오후 3시쯤 비가 세차게 쏟아지기 시작했어요.' WHERE id = 'w_weather_A2_18';
UPDATE words SET example_en_2 = 'The heavy snowfall overnight made the city look completely white.', example_ko_2 = '밤새 폭설이 내려서 도시가 완전히 하얗게 변했어요.', example_en_3 = 'The annual snowfall in this mountain region can reach two metres.', example_ko_3 = '이 산악 지역의 연간 강설량은 2미터에 달할 수 있어요.', example_en_4 = 'Snowfall is quite rare in the southern parts of Korea.', example_ko_4 = '한국 남부 지방에서는 강설이 꽤 드물어요.', example_en_5 = 'Children love the first snowfall of winter — they run straight outside.', example_ko_5 = '아이들은 겨울의 첫 강설을 좋아해서 바로 밖으로 뛰어나가요.' WHERE id = 'w_weather_A2_19';
UPDATE words SET example_en_2 = 'It is freezing outside — please turn on the heating.', example_ko_2 = '밖이 꽁꽁 얼어붙을 것 같으니까 난방을 켜 주세요.', example_en_3 = 'My fingers were freezing after waiting at the bus stop for so long.', example_ko_3 = '버스 정류장에서 너무 오래 기다렸더니 손가락이 얼어붙을 것 같았어요.', example_en_4 = 'The water pipes burst because of the freezing temperatures last night.', example_ko_4 = '어젯밤 영하의 기온 때문에 수도관이 터졌어요.', example_en_5 = 'It is freezing in here — can we close the window please?', example_ko_5 = '여기 너무 추워요 — 창문을 닫아도 될까요?' WHERE id = 'w_weather_A2_20';
UPDATE words SET example_en_2 = 'The humid tropical climate makes everything feel damp all year round.', example_ko_2 = '습한 열대 기후 때문에 일 년 내내 모든 것이 축축하게 느껴져요.', example_en_3 = 'Tropical fish need warm and humid conditions to survive.', example_ko_3 = '열대어는 생존하기 위해 따뜻하고 습한 환경이 필요해요.', example_en_4 = 'The museum was kept humid to preserve the ancient wooden artefacts.', example_ko_4 = '고대 목재 유물을 보존하기 위해 박물관 내 습도가 유지됐어요.', example_en_5 = 'Humid weather makes my joints ache, especially in the knees.', example_ko_5 = '습한 날씨에는 특히 무릎 관절이 아파요.' WHERE id = 'w_weather_A2_21';
UPDATE words SET example_en_2 = 'A sudden gust of wind blew the newspapers off the table.', example_ko_2 = '갑작스러운 돌풍이 신문지를 탁자에서 날려버렸어요.', example_en_3 = 'Strong gusts of wind are making it dangerous to drive on the bridge.', example_ko_3 = '강한 돌풍 때문에 다리 위에서 운전하기가 위험해요.', example_en_4 = 'The wind came in gusts rather than blowing steadily.', example_ko_4 = '바람이 꾸준히 불지 않고 돌풍으로 불어왔어요.', example_en_5 = 'A gust of wind slammed the door shut while I was outside.', example_ko_5 = '제가 밖에 있는 동안 돌풍이 문을 쾅 닫아버렸어요.' WHERE id = 'w_weather_A2_22';
UPDATE words SET example_en_2 = 'The damp walls in the basement indicated a water leak somewhere.', example_ko_2 = '지하실의 축축한 벽은 어딘가에 물이 새고 있다는 것을 나타냈어요.', example_en_3 = 'My clothes feel damp because of the humidity in the air.', example_ko_3 = '공기 중의 습기 때문에 옷이 축축하게 느껴져요.', example_en_4 = 'The damp weather is making my knees ache today.', example_ko_4 = '습한 날씨 때문에 오늘 무릎이 아파요.', example_en_5 = 'Open the windows to air out the damp smell in the room.', example_ko_5 = '방의 축축한 냄새를 환기시키려면 창문을 여세요.' WHERE id = 'w_weather_A2_23';
UPDATE words SET example_en_2 = 'The muggy weather made everyone feel tired and irritable.', example_ko_2 = '후텁지근한 날씨에 모두가 피곤하고 짜증스럽게 느꼈어요.', example_en_3 = 'It gets very muggy in Seoul in July and August.', example_ko_3 = '서울은 7월과 8월에 매우 후텁지근해져요.', example_en_4 = 'I cannot sleep well on muggy nights without a fan.', example_ko_4 = '후텁지근한 밤에는 선풍기 없이는 잘 수가 없어요.', example_en_5 = 'The muggy air in the greenhouse was almost unbearable.', example_ko_5 = '온실 안의 후텁지근한 공기가 거의 견딜 수 없을 정도였어요.' WHERE id = 'w_weather_A2_24';
UPDATE words SET example_en_2 = 'The sky is clear today — perfect for stargazing tonight.', example_ko_2 = '오늘 하늘이 맑아서 오늘 밤 별 보기에 완벽해요.', example_en_3 = 'After the storm, the air was clear and fresh.', example_ko_3 = '폭풍 후에 공기가 맑고 상쾌해졌어요.', example_en_4 = 'We finally got a clear day after almost two weeks of rain.', example_ko_4 = '거의 2주간의 비 끝에 드디어 맑은 날이 왔어요.', example_en_5 = 'Clear skies are expected for the rest of the week.', example_ko_5 = '이번 주 나머지 기간에는 맑은 하늘이 예상돼요.' WHERE id = 'w_weather_A2_25';
UPDATE words SET example_en_2 = 'We enjoyed a sunny spell in the afternoon between the rain showers.', example_ko_2 = '소나기 사이 오후에 잠깐 햇빛이 나는 시간을 즐겼어요.', example_en_3 = 'There is expected to be a brief sunny spell around midday.', example_ko_3 = '낮쯤에 잠깐 햇빛이 날 것으로 예상돼요.', example_en_4 = 'The children went outside during the sunny spell to play.', example_ko_4 = '아이들이 햇빛이 나는 동안 밖에 나가서 놀았어요.', example_en_5 = 'Make the most of the sunny spell — it won''t last long.', example_ko_5 = '햇빛 나는 시간을 최대한 활용하세요 — 오래 지속되지 않을 거예요.' WHERE id = 'w_weather_A2_26';
UPDATE words SET example_en_2 = 'The wind chill made the five-degree day feel like minus ten.', example_ko_2 = '체감 온도 때문에 5도 날씨가 영하 10도처럼 느껴졌어요.', example_en_3 = 'Always consider the wind chill before deciding what to wear in winter.', example_ko_3 = '겨울에 뭘 입을지 결정하기 전에 항상 체감 온도를 고려하세요.', example_en_4 = 'The wind chill advisory warned of dangerously cold conditions tonight.', example_ko_4 = '체감 온도 주의보가 오늘 밤 위험할 정도의 추위를 경고했어요.', example_en_5 = 'High winds increased the wind chill factor significantly.', example_ko_5 = '강한 바람이 체감 온도 지수를 크게 높였어요.' WHERE id = 'w_weather_A2_27';
UPDATE words SET example_en_2 = 'The total rainfall this month has already exceeded the monthly average.', example_ko_2 = '이번 달 총 강우량이 이미 월평균을 초과했어요.', example_en_3 = 'Farmers depend on adequate rainfall for their crops to grow well.', example_ko_3 = '농부들은 농작물이 잘 자라려면 충분한 강우량이 필요해요.', example_en_4 = 'Rainfall in this region is usually highest in June and July.', example_ko_4 = '이 지역의 강우량은 보통 6월과 7월에 가장 높아요.', example_en_5 = 'Insufficient rainfall can lead to droughts and water shortages.', example_ko_5 = '강우량이 부족하면 가뭄과 물 부족으로 이어질 수 있어요.' WHERE id = 'w_weather_A2_28';
UPDATE words SET example_en_2 = 'Dark thunder clouds were forming on the horizon before the storm.', example_ko_2 = '폭풍 전에 지평선에 먹구름이 형성되고 있었어요.', example_en_3 = 'We could see thunder clouds building up over the mountains.', example_ko_3 = '산 위에 먹구름이 쌓이는 것을 볼 수 있었어요.', example_en_4 = 'The thunder clouds brought heavy rain and strong winds.', example_ko_4 = '먹구름이 폭우와 강풍을 몰고 왔어요.', example_en_5 = 'Thunder clouds covered the sky and blocked the sunlight completely.', example_ko_5 = '먹구름이 하늘을 덮어 햇빛을 완전히 차단했어요.' WHERE id = 'w_weather_A2_29';
UPDATE words SET example_en_2 = 'Be careful on the steps — they are icy this morning.', example_ko_2 = '계단을 조심하세요 — 오늘 아침 얼어 있어요.', example_en_3 = 'The road conditions were dangerously icy after the freezing rain.', example_ko_3 = '얼어붙는 비가 온 후 도로 상태가 위험할 정도로 빙판이었어요.', example_en_4 = 'The icy pavement made it very difficult to walk without slipping.', example_ko_4 = '빙판 보도 때문에 미끄러지지 않고 걷기가 매우 어려웠어요.', example_en_5 = 'We had to cancel the morning run because of icy conditions outside.', example_ko_5 = '밖의 빙판 상태 때문에 아침 달리기를 취소해야 했어요.' WHERE id = 'w_weather_A2_30';
UPDATE words SET example_en_2 = 'The downpour lasted only ten minutes but soaked everything.', example_ko_2 = '집중호우는 10분밖에 안 됐지만 모든 것을 흠뻑 적셨어요.', example_en_3 = 'We were caught in a sudden downpour while walking in the park.', example_ko_3 = '공원을 걷다가 갑작스러운 집중호우를 맞았어요.', example_en_4 = 'A sudden downpour ruined the outdoor wedding ceremony.', example_ko_4 = '갑작스러운 집중호우가 야외 결혼식을 망쳤어요.', example_en_5 = 'Take shelter immediately — that downpour looks very heavy.', example_ko_5 = '즉시 피하세요 — 저 집중호우가 매우 심해 보여요.' WHERE id = 'w_weather_A2_31';
UPDATE words SET example_en_2 = 'A cloudburst flooded the city streets within minutes yesterday.', example_ko_2 = '어제 갑작스러운 집중호우가 몇 분 만에 도시 거리를 침수시켰어요.', example_en_3 = 'We were completely unprepared for the cloudburst that hit at noon.', example_ko_3 = '정오에 쏟아진 집중호우에 완전히 대비가 안 됐어요.', example_en_4 = 'A cloudburst can release large amounts of rain in a very short time.', example_ko_4 = '집중호우는 매우 짧은 시간에 많은 양의 비를 쏟아낼 수 있어요.', example_en_5 = 'The cloudburst overflowed the drains and caused localised flooding.', example_ko_5 = '집중호우가 배수구를 넘쳐흐르게 해서 국지적인 침수를 일으켰어요.' WHERE id = 'w_weather_A2_32';
UPDATE words SET example_en_2 = 'A thin mist hung over the valley early in the morning.', example_ko_2 = '이른 아침 계곡 위에 옅은 안개가 드리워져 있었어요.', example_en_3 = 'The mist made the old castle look mysterious and dramatic.', example_ko_3 = '안개가 오래된 성을 신비롭고 극적으로 보이게 했어요.', example_en_4 = 'A light mist was rising from the river as the sun came up.', example_ko_4 = '해가 뜨면서 강에서 옅은 안개가 피어올랐어요.', example_en_5 = 'The coastal mist usually clears by nine or ten in the morning.', example_ko_5 = '해안 안개는 보통 오전 9시나 10시쯤에 걷혀요.' WHERE id = 'w_weather_A2_33';
UPDATE words SET example_en_2 = 'Sleet is not as heavy as snow but it can still make roads very slippery.', example_ko_2 = '진눈깨비는 눈만큼 무겁지는 않지만 도로를 매우 미끄럽게 만들 수 있어요.', example_en_3 = 'Sleet fell through the night and turned into ice by morning.', example_ko_3 = '밤새 진눈깨비가 내려서 아침이 되자 얼음이 됐어요.', example_en_4 = 'The sleet made driving conditions very hazardous on the motorway.', example_ko_4 = '진눈깨비가 고속도로의 운전 환경을 매우 위험하게 만들었어요.', example_en_5 = 'Sleet is common in Korea during the transitional months of November and March.', example_ko_5 = '진눈깨비는 한국에서 11월과 3월 같은 과도기에 흔해요.' WHERE id = 'w_weather_A2_34';
UPDATE words SET example_en_2 = 'The hazy sky made it hard to see the mountains in the distance.', example_ko_2 = '뿌연 하늘 때문에 멀리 있는 산을 보기 어려웠어요.', example_en_3 = 'Hazy conditions are common in spring due to yellow dust from China.', example_ko_3 = '봄에는 중국에서 오는 황사 때문에 뿌연 상태가 흔해요.', example_en_4 = 'It was a hazy morning, but the view from the hilltop was still beautiful.', example_ko_4 = '뿌연 아침이었지만 언덕 위에서의 경치는 여전히 아름다웠어요.', example_en_5 = 'The city skyline looked ghostly through the hazy summer air.', example_ko_5 = '뿌연 여름 공기 속으로 도시 스카이라인이 유령 같아 보였어요.' WHERE id = 'w_weather_A2_35';
UPDATE words SET example_en_2 = 'The humidity in Seoul during July can make the heat feel unbearable.', example_ko_2 = '7월 서울의 습도는 더위를 견디기 힘들게 만들 수 있어요.', example_en_3 = 'High humidity encourages the growth of mould in enclosed spaces.', example_ko_3 = '높은 습도는 밀폐된 공간에서 곰팡이 성장을 촉진해요.', example_en_4 = 'The humidity level indoors should ideally be between 40 and 60 percent.', example_ko_4 = '실내 습도 수준은 이상적으로 40에서 60퍼센트 사이여야 해요.', example_en_5 = 'A dehumidifier helps reduce humidity and makes the air more comfortable.', example_ko_5 = '제습기는 습도를 낮추어 공기를 더 쾌적하게 만드는 데 도움이 돼요.' WHERE id = 'w_weather_B1_01';
UPDATE words SET example_en_2 = 'Meteorologists measure precipitation using a rain gauge.', example_ko_2 = '기상학자들은 우량계를 사용해서 강수량을 측정해요.', example_en_3 = 'Annual precipitation in this region is significantly higher than the national average.', example_ko_3 = '이 지역의 연간 강수량은 전국 평균보다 훨씬 높아요.', example_en_4 = 'Precipitation in the form of snow is common above 600 metres altitude.', example_ko_4 = '해발 600미터 이상에서는 눈 형태의 강수가 흔해요.', example_en_5 = 'A lack of precipitation over several months can lead to drought conditions.', example_ko_5 = '몇 달 동안 강수 부족이 지속되면 가뭄 상태로 이어질 수 있어요.' WHERE id = 'w_weather_B1_02';
UPDATE words SET example_en_2 = 'Poor visibility caused several accidents on the motorway this morning.', example_ko_2 = '오늘 아침 낮은 시야 때문에 고속도로에서 몇 건의 사고가 났어요.', example_en_3 = 'Visibility dropped to less than 100 metres due to the dense fog.', example_ko_3 = '짙은 안개 때문에 시야가 100미터 이하로 떨어졌어요.', example_en_4 = 'The pilot reported excellent visibility during the approach to the airport.', example_ko_4 = '조종사는 공항 접근 중에 시야가 매우 좋다고 보고했어요.', example_en_5 = 'Wearing high-visibility clothing is important when cycling in low visibility conditions.', example_ko_5 = '시야가 낮은 상태에서 자전거를 탈 때는 고시인성 의류를 입는 것이 중요해요.' WHERE id = 'w_weather_B1_03';
UPDATE words SET example_en_2 = 'The prolonged heatwave caused widespread power outages across the country.', example_ko_2 = '장기간의 폭염이 전국에 걸쳐 광범위한 정전을 일으켰어요.', example_en_3 = 'Elderly people and young children are most vulnerable during a heatwave.', example_ko_3 = '노인과 어린 아이들이 폭염에 가장 취약해요.', example_en_4 = 'The heatwave broke records in several European countries this summer.', example_ko_4 = '이번 여름 폭염이 여러 유럽 국가에서 기록을 경신했어요.', example_en_5 = 'During a heatwave, health authorities recommend staying out of the sun between noon and three.', example_ko_5 = '폭염 중에는 보건 당국이 정오부터 3시 사이에 햇빛을 피하도록 권고해요.' WHERE id = 'w_weather_B1_04';
UPDATE words SET example_en_2 = 'The severe drought reduced the reservoir to less than twenty percent capacity.', example_ko_2 = '심각한 가뭄으로 저수지가 용량의 20퍼센트 이하로 줄었어요.', example_en_3 = 'Farmers face significant losses when drought conditions persist for several months.', example_ko_3 = '가뭄 상태가 몇 달 동안 지속되면 농부들이 큰 손실을 입어요.', example_en_4 = 'The government declared a state of emergency due to the ongoing drought.', example_ko_4 = '정부는 계속되는 가뭄으로 인해 비상사태를 선포했어요.', example_en_5 = 'Drought conditions are becoming more frequent as global temperatures rise.', example_ko_5 = '지구 기온이 오르면서 가뭄 상태가 더 자주 발생하고 있어요.' WHERE id = 'w_weather_B1_05';
UPDATE words SET example_en_2 = 'The blizzard brought more than a metre of snow overnight.', example_ko_2 = '눈보라가 밤새 1미터 이상의 눈을 가져왔어요.', example_en_3 = 'Emergency services were stretched to the limit during the blizzard.', example_ko_3 = '눈보라 동안 응급 서비스가 한계까지 동원됐어요.', example_en_4 = 'Never attempt to drive during a blizzard unless it is absolutely necessary.', example_ko_4 = '꼭 필요한 경우가 아니면 눈보라 동안 절대 운전하려 하지 마세요.', example_en_5 = 'The blizzard left the entire city paralysed for two days.', example_ko_5 = '눈보라가 이틀 동안 도시 전체를 마비시켰어요.' WHERE id = 'w_weather_B1_06';
UPDATE words SET example_en_2 = 'The sky has been overcast all morning, but rain is not expected until evening.', example_ko_2 = '오전 내내 하늘이 흐렸지만 저녁까지는 비가 예상되지 않아요.', example_en_3 = 'An overcast sky provides natural, diffused light that is ideal for photography.', example_ko_3 = '흐린 하늘은 사진 찍기에 이상적인 자연스럽고 부드러운 빛을 제공해요.', example_en_4 = 'The overcast conditions made the landscape look rather grey and uninviting.', example_ko_4 = '흐린 날씨가 풍경을 다소 회색빛으로 매력 없어 보이게 했어요.', example_en_5 = 'Despite the overcast weather, we still enjoyed our walk along the coast.', example_ko_5 = '흐린 날씨에도 불구하고 해안 산책을 즐겼어요.' WHERE id = 'w_weather_B1_07';
UPDATE words SET example_en_2 = 'The mild temperatures made it comfortable to eat dinner outside.', example_ko_2 = '온화한 기온 덕분에 밖에서 저녁을 먹기에 편안했어요.', example_en_3 = 'The region enjoys a mild Mediterranean climate throughout the year.', example_ko_3 = '이 지역은 일 년 내내 온화한 지중해 기후를 즐길 수 있어요.', example_en_4 = 'This winter has been unusually mild — we have had almost no frost.', example_ko_4 = '이번 겨울은 유난히 온화해서 서리가 거의 없었어요.', example_en_5 = 'A mild climate is one of the many reasons people choose to retire here.', example_ko_5 = '온화한 기후는 사람들이 이곳에서 은퇴를 선택하는 여러 이유 중 하나예요.' WHERE id = 'w_weather_B1_08';
UPDATE words SET example_en_2 = 'It turned chilly as the sun went down, so we moved inside.', example_ko_2 = '해가 지면서 쌀쌀해져서 안으로 들어갔어요.', example_en_3 = 'The chilly autumn air reminds me that summer is truly over.', example_ko_3 = '쌀쌀한 가을 공기가 여름이 정말 끝났다는 것을 상기시켜 줘요.', example_en_4 = 'A chilly wind from the north reduced the temperature significantly.', example_ko_4 = '북쪽에서 불어온 쌀쌀한 바람이 기온을 크게 낮췄어요.', example_en_5 = 'Even on a sunny day, the chilly sea breeze keeps the temperature down.', example_ko_5 = '맑은 날에도 쌀쌀한 해풍이 기온을 낮게 유지시켜 줘요.' WHERE id = 'w_weather_B1_09';
UPDATE words SET example_en_2 = 'The tropical climate supports a huge diversity of plant and animal species.', example_ko_2 = '열대 기후는 다양한 동식물 종의 서식을 뒷받침해요.', example_en_3 = 'Tropical storms form over warm ocean waters near the equator.', example_ko_3 = '열대 폭풍은 적도 근처 따뜻한 해수면 위에서 형성돼요.', example_en_4 = 'The tropical heat and humidity made acclimatisation difficult for the first few days.', example_ko_4 = '열대의 더위와 습도가 처음 며칠 동안 적응을 어렵게 만들었어요.', example_en_5 = 'Tropical regions typically experience two seasons: wet and dry.', example_ko_5 = '열대 지역은 보통 건기와 우기의 두 계절을 경험해요.' WHERE id = 'w_weather_B1_10';
UPDATE words SET example_en_2 = 'A high pressure system is bringing clear, settled weather to the region.', example_ko_2 = '고기압이 이 지역에 맑고 안정된 날씨를 가져오고 있어요.', example_en_3 = 'The atmospheric pressure dropped sharply before the arrival of the storm.', example_ko_3 = '폭풍이 도착하기 전에 대기압이 급격히 떨어졌어요.', example_en_4 = 'A barometer measures atmospheric pressure and can indicate incoming weather changes.', example_ko_4 = '기압계는 대기압을 측정하고 다가오는 날씨 변화를 나타낼 수 있어요.', example_en_5 = 'Low pressure systems are typically associated with unsettled and wet weather.', example_ko_5 = '저기압 시스템은 보통 불안정하고 비 오는 날씨와 관련이 있어요.' WHERE id = 'w_weather_B1_11';
UPDATE words SET example_en_2 = 'A cold front is advancing from the northwest and will bring rain by evening.', example_ko_2 = '북서쪽에서 한랭 전선이 접근하고 있어서 저녁까지 비가 올 거예요.', example_en_3 = 'The boundary between two air masses is called a weather front.', example_ko_3 = '두 공기 덩어리 사이의 경계를 기상 전선이라고 해요.', example_en_4 = 'A warm front brings slowly rising temperatures and prolonged rainfall.', example_ko_4 = '온난 전선은 서서히 오르는 기온과 장기간의 강우를 가져와요.', example_en_5 = 'The front moved through overnight, bringing dramatic weather changes.', example_ko_5 = '전선이 밤새 통과하면서 극적인 날씨 변화를 가져왔어요.' WHERE id = 'w_weather_B1_12';
UPDATE words SET example_en_2 = 'A gale warning has been issued for all coastal areas tonight.', example_ko_2 = '오늘 밤 모든 해안 지역에 강풍 경보가 발령됐어요.', example_en_3 = 'The ferry crossing was cancelled due to gale-force winds in the channel.', example_ko_3 = '해협의 강풍 때문에 페리 도항이 취소됐어요.', example_en_4 = 'Gusts during the gale reached speeds of 120 kilometres per hour.', example_ko_4 = '강풍 중 돌풍이 시속 120킬로미터의 속도에 달했어요.', example_en_5 = 'Gales are most common in coastal areas during autumn and winter.', example_ko_5 = '강풍은 가을과 겨울 동안 해안 지역에서 가장 흔해요.' WHERE id = 'w_weather_B1_13';
UPDATE words SET example_en_2 = 'A severe thunderstorm knocked out electricity to thousands of homes.', example_ko_2 = '심한 뇌우가 수천 가정의 전기를 끊었어요.', example_en_3 = 'Take shelter immediately when a thunderstorm approaches.', example_ko_3 = '뇌우가 접근할 때는 즉시 피하세요.', example_en_4 = 'The thunderstorm lasted for over two hours and produced large hailstones.', example_ko_4 = '뇌우가 2시간 넘게 지속되면서 큰 우박이 내렸어요.', example_en_5 = 'The children were frightened by the thunderstorm and could not sleep.', example_ko_5 = '아이들이 뇌우에 놀라서 잠을 자지 못했어요.' WHERE id = 'w_weather_B1_14';
UPDATE words SET example_en_2 = 'The scorching sun in the afternoon made outdoor exercise dangerous.', example_ko_2 = '오후의 뜨거운 태양이 야외 운동을 위험하게 만들었어요.', example_en_3 = 'It was scorching hot on the beach, so we stayed under the umbrella.', example_ko_3 = '해변이 뜨겁게 작열해서 파라솔 아래에 머물렀어요.', example_en_4 = 'Even the shade offered little relief from the scorching temperatures.', example_ko_4 = '뜨겁게 작열하는 기온 앞에서는 그늘도 거의 도움이 되지 않았어요.', example_en_5 = 'Apply sunscreen before going out in scorching weather to protect your skin.', example_ko_5 = '뜨거운 날씨에 나가기 전에 선크림을 바르세요 피부를 보호하기 위해서요.' WHERE id = 'w_weather_B1_15';
UPDATE words SET example_en_2 = 'The breezy conditions made the summer heat much more bearable.', example_ko_2 = '산들바람 덕분에 여름 더위가 훨씬 견딜 만해졌어요.', example_en_3 = 'It was a beautiful, breezy day — perfect for flying a kite.', example_ko_3 = '바람이 살랑살랑 부는 아름다운 날이었어요 — 연 날리기에 딱 좋았어요.', example_en_4 = 'A breezy day is ideal for sailing on the lake.', example_ko_4 = '바람이 솔솔 부는 날은 호수에서 항해하기에 이상적이에요.', example_en_5 = 'The breezy evening made sitting on the terrace very pleasant.', example_ko_5 = '바람이 솔솔 부는 저녁에 테라스에 앉는 것이 매우 즐거웠어요.' WHERE id = 'w_weather_B1_16';
UPDATE words SET example_en_2 = 'The humid subtropical climate means hot, wet summers and mild winters.', example_ko_2 = '습한 아열대 기후는 덥고 비 오는 여름과 온화한 겨울을 의미해요.', example_en_3 = 'Many cities in southern China have a humid subtropical climate.', example_ko_3 = '중국 남부의 많은 도시들은 습한 아열대 기후를 가지고 있어요.', example_en_4 = 'Agriculture in humid subtropical regions benefits from year-round rainfall.', example_ko_4 = '습한 아열대 지역의 농업은 연중 강우의 혜택을 받아요.', example_en_5 = 'The humidity in humid subtropical climates can be very challenging in summer.', example_ko_5 = '습한 아열대 기후의 습도는 여름에 매우 힘들 수 있어요.' WHERE id = 'w_weather_B1_17';
UPDATE words SET example_en_2 = 'Drivers were warned about slippery road conditions following overnight rain.', example_ko_2 = '밤새 비가 온 후 운전자들에게 미끄러운 도로 상태에 대한 경고가 내려졌어요.', example_en_3 = 'Slippery road conditions caused a major accident on the highway this morning.', example_ko_3 = '오늘 아침 미끄러운 도로 상태가 고속도로에서 큰 사고를 유발했어요.', example_en_4 = 'Warning signs were put up to alert drivers to slippery road conditions ahead.', example_ko_4 = '앞쪽의 미끄러운 도로 상태를 운전자들에게 알리기 위해 경고 표지판이 세워졌어요.', example_en_5 = 'Reduce your speed on slippery road surfaces and increase your following distance.', example_ko_5 = '미끄러운 도로에서는 속도를 줄이고 차간 거리를 늘리세요.' WHERE id = 'w_weather_B1_18';
UPDATE words SET example_en_2 = 'The pollen count is very high today, which is bad news for allergy sufferers.', example_ko_2 = '오늘 화분 수치가 매우 높아서 알레르기 환자들에게 좋지 않은 소식이에요.', example_en_3 = 'Check the pollen count before heading outside if you suffer from hay fever.', example_ko_3 = '꽃가루 알레르기가 있으면 외출하기 전에 화분 수치를 확인하세요.', example_en_4 = 'The pollen count tends to peak in the morning on warm, dry, and windy days.', example_ko_4 = '화분 수치는 따뜻하고 건조하며 바람 부는 날 오전에 최고조에 달하는 경향이 있어요.', example_en_5 = 'Doctors recommend antihistamines on days when the pollen count is high.', example_ko_5 = '의사들은 화분 수치가 높은 날에는 항히스타민제를 권해요.' WHERE id = 'w_weather_B1_19';
UPDATE words SET example_en_2 = 'The heat index reached 48 degrees, making outdoor work very dangerous.', example_ko_2 = '열지수가 48도에 달해서 야외 작업이 매우 위험했어요.', example_en_3 = 'The heat index accounts for both temperature and humidity to reflect how hot it feels.', example_ko_3 = '열지수는 얼마나 덥게 느껴지는지를 반영하기 위해 온도와 습도를 모두 고려해요.', example_en_4 = 'When the heat index is above 40, health authorities recommend limiting outdoor activity.', example_ko_4 = '열지수가 40을 초과하면 보건 당국은 야외 활동을 제한하도록 권고해요.', example_en_5 = 'The heat index can be significantly higher than the actual air temperature on humid days.', example_ko_5 = '습한 날에는 열지수가 실제 기온보다 훨씬 높을 수 있어요.' WHERE id = 'w_weather_B1_20';
UPDATE words SET example_en_2 = 'The wind speed during the typhoon exceeded 200 kilometres per hour.', example_ko_2 = '태풍 중 풍속이 시속 200킬로미터를 초과했어요.', example_en_3 = 'Meteorologists measure wind speed using an anemometer.', example_ko_3 = '기상학자들은 풍속계를 사용해서 풍속을 측정해요.', example_en_4 = 'The wind speed forecast for tonight is 60 to 80 kilometres per hour.', example_ko_4 = '오늘 밤 풍속 예보는 시속 60에서 80킬로미터예요.', example_en_5 = 'Knowing the wind speed is important when planning outdoor events.', example_ko_5 = '야외 행사를 계획할 때 풍속을 아는 것이 중요해요.' WHERE id = 'w_weather_B1_21';
UPDATE words SET example_en_2 = 'The barometer in our hallway has been dropping steadily since yesterday.', example_ko_2 = '복도의 기압계가 어제부터 꾸준히 떨어지고 있어요.', example_en_3 = 'A rapidly falling barometer reading often indicates an approaching storm.', example_ko_3 = '기압계 수치가 빠르게 떨어지면 종종 폭풍이 접근하고 있다는 신호예요.', example_en_4 = 'Traditional fishermen used a barometer to predict weather changes at sea.', example_ko_4 = '전통적인 어부들은 바다에서 날씨 변화를 예측하기 위해 기압계를 사용했어요.', example_en_5 = 'The barometer reading has stabilised, suggesting the weather will settle down.', example_ko_5 = '기압계 수치가 안정돼서 날씨가 안정될 것 같아요.' WHERE id = 'w_weather_B1_22';
UPDATE words SET example_en_2 = 'The UV index today is 9 — please wear sunscreen and protective clothing.', example_ko_2 = '오늘 자외선 지수는 9예요 — 선크림과 보호 의류를 착용하세요.', example_en_3 = 'A UV index above 8 is considered very high and requires full protection.', example_ko_3 = '자외선 지수 8 이상은 매우 높은 것으로 간주되어 완전한 차단이 필요해요.', example_en_4 = 'Check the UV index before spending a long time outdoors in summer.', example_ko_4 = '여름에 야외에서 오랜 시간을 보내기 전에 자외선 지수를 확인하세요.', example_en_5 = 'The UV index tends to be highest between 10 in the morning and 2 in the afternoon.', example_ko_5 = '자외선 지수는 오전 10시에서 오후 2시 사이에 가장 높은 경향이 있어요.' WHERE id = 'w_weather_B1_23';
UPDATE words SET example_en_2 = 'A flood warning was issued for the river valleys after days of heavy rain.', example_ko_2 = '며칠간의 폭우 후에 강 계곡에 홍수 경보가 발령됐어요.', example_en_3 = 'Residents in low-lying areas were urged to evacuate ahead of the flood warning.', example_ko_3 = '저지대 주민들은 홍수 경보에 앞서 대피하도록 촉구됐어요.', example_en_4 = 'The flood warning system gives people valuable time to prepare and move to safety.', example_ko_4 = '홍수 경보 시스템은 사람들이 대비하고 안전한 곳으로 이동할 소중한 시간을 줘요.', example_en_5 = 'A flood warning does not necessarily mean flooding will occur, but preparation is essential.', example_ko_5 = '홍수 경보가 반드시 침수가 발생한다는 것을 의미하지는 않지만 대비는 필수예요.' WHERE id = 'w_weather_B1_24';
UPDATE words SET example_en_2 = 'The air quality in the city deteriorated significantly due to smog and fine dust.', example_ko_2 = '스모그와 미세먼지로 인해 도시의 공기 질이 크게 악화됐어요.', example_en_3 = 'Doctors advise checking the air quality index before exercising outdoors.', example_ko_3 = '의사들은 야외 운동 전에 공기 질 지수를 확인하도록 권고해요.', example_en_4 = 'Good air quality is essential for the health and well-being of residents.', example_ko_4 = '좋은 공기 질은 주민들의 건강과 복지에 필수적이에요.', example_en_5 = 'Air quality tends to be best after rainfall, which washes pollutants out of the air.', example_ko_5 = '공기 질은 비가 내린 후 공기 중 오염 물질을 씻어 내므로 가장 좋은 경향이 있어요.' WHERE id = 'w_weather_B1_25';
UPDATE words SET example_en_2 = 'Smog levels in the city were so high that visibility fell to just a few hundred metres.', example_ko_2 = '도시의 스모그 수준이 너무 높아서 시야가 불과 수백 미터로 떨어졌어요.', example_en_3 = 'Smog is formed when vehicle emissions react with sunlight.', example_ko_3 = '스모그는 차량 배출 가스가 햇빛과 반응할 때 형성돼요.', example_en_4 = 'The government introduced an odd-even driving ban to reduce smog levels.', example_ko_4 = '정부는 스모그 수준을 낮추기 위해 홀짝 운행 제한을 도입했어요.', example_en_5 = 'Breathing smog-polluted air regularly can cause serious respiratory problems.', example_ko_5 = '스모그로 오염된 공기를 정기적으로 마시면 심각한 호흡기 문제가 생길 수 있어요.' WHERE id = 'w_weather_B1_26';
UPDATE words SET example_en_2 = 'The dew point rose above 20 degrees, making the night very sticky and uncomfortable.', example_ko_2 = '이슬점이 20도 이상으로 올라가서 밤이 매우 끈적하고 불편했어요.', example_en_3 = 'A high dew point indicates that the air contains a large amount of moisture.', example_ko_3 = '높은 이슬점은 공기 중에 많은 수분이 포함되어 있다는 것을 나타내요.', example_en_4 = 'The dew point is a more reliable indicator of comfort than relative humidity alone.', example_ko_4 = '이슬점은 상대 습도만으로 보는 것보다 쾌적함을 더 신뢰할 수 있게 나타내는 지표예요.', example_en_5 = 'Meteorologists track the dew point to forecast fog and precipitation.', example_ko_5 = '기상학자들은 안개와 강수를 예보하기 위해 이슬점을 추적해요.' WHERE id = 'w_weather_B1_27';
UPDATE words SET example_en_2 = 'The wind direction shifted from south to north as the cold front passed.', example_ko_2 = '한랭 전선이 통과하면서 바람 방향이 남쪽에서 북쪽으로 바뀌었어요.', example_en_3 = 'Sailors pay close attention to wind direction when planning a voyage.', example_ko_3 = '선원들은 항해를 계획할 때 바람 방향에 세심한 주의를 기울여요.', example_en_4 = 'A wind direction indicator, or wind vane, points in the direction from which the wind blows.', example_ko_4 = '바람 방향 표시기, 즉 풍향계는 바람이 불어오는 방향을 가리켜요.', example_en_5 = 'Wind direction plays a key role in determining how quickly a wildfire spreads.', example_ko_5 = '바람 방향은 산불이 얼마나 빠르게 번지는지에 핵심적인 역할을 해요.' WHERE id = 'w_weather_B1_28';
UPDATE words SET example_en_2 = 'A severe weather alert was issued for the entire eastern coast of the country.', example_ko_2 = '전국 동해안 전체에 악기상 경보가 발령됐어요.', example_en_3 = 'Severe weather conditions forced the cancellation of all flights from the airport.', example_ko_3 = '악기상 상태로 인해 공항에서 모든 항공편이 취소됐어요.', example_en_4 = 'It is important to monitor severe weather alerts and follow official guidance.', example_ko_4 = '악기상 경보를 모니터링하고 공식 지침을 따르는 것이 중요해요.', example_en_5 = 'The severe weather caused millions of pounds worth of damage to infrastructure.', example_ko_5 = '악기상이 수백만 파운드 상당의 인프라 피해를 야기했어요.' WHERE id = 'w_weather_B1_29';
UPDATE words SET example_en_2 = 'The emergency shelter provided food and warmth to hundreds of displaced residents.', example_ko_2 = '비상 대피소가 수백 명의 이재민에게 음식과 온기를 제공했어요.', example_en_3 = 'Please take shelter immediately — the storm is approaching very fast.', example_ko_3 = '즉시 대피하세요 — 폭풍이 매우 빠르게 접근하고 있어요.', example_en_4 = 'A well-built storm shelter can protect lives during a tornado or hurricane.', example_ko_4 = '잘 지어진 폭풍 대피소는 토네이도나 허리케인 동안 생명을 보호할 수 있어요.', example_en_5 = 'The hikers found shelter in a cave when the weather turned dangerous.', example_ko_5 = '날씨가 위험하게 변하자 등산객들은 동굴에서 피난처를 찾았어요.' WHERE id = 'w_weather_B1_30';
UPDATE words SET example_en_2 = 'A frost warning is in effect tonight — protect your outdoor plants.', example_ko_2 = '오늘 밤 서리 경보가 발효 중이에요 — 야외 식물을 보호하세요.', example_en_3 = 'The frost warning caused farmers to rush to cover their crops before dawn.', example_ko_3 = '서리 경보로 인해 농부들이 새벽 전에 서둘러 농작물을 덮었어요.', example_en_4 = 'Even a mild frost warning should be taken seriously if you have sensitive plants.', example_ko_4 = '민감한 식물이 있다면 가벼운 서리 경보라도 진지하게 받아들여야 해요.', example_en_5 = 'The frost warning was lifted by midday as temperatures rose above zero.', example_ko_5 = '기온이 영상으로 오르면서 서리 경보가 낮이 되자 해제됐어요.' WHERE id = 'w_weather_B1_31';
UPDATE words SET example_en_2 = 'A weather advisory was issued urging people to avoid unnecessary travel.', example_ko_2 = '불필요한 이동을 자제할 것을 촉구하는 기상 주의보가 발령됐어요.', example_en_3 = 'The advisory recommended that residents in flood-prone areas move to higher ground.', example_ko_3 = '주의보는 홍수 취약 지역 주민들에게 고지대로 이동할 것을 권고했어요.', example_en_4 = 'A heat advisory was extended for a further three days due to ongoing high temperatures.', example_ko_4 = '계속되는 고온으로 인해 폭염 주의보가 3일 더 연장됐어요.', example_en_5 = 'Always follow government advisories during periods of extreme weather.', example_ko_5 = '극한 날씨 기간에는 항상 정부 주의보를 따르세요.' WHERE id = 'w_weather_B1_32';
UPDATE words SET example_en_2 = 'The trough of low pressure brought unsettled, wet weather to the region.', example_ko_2 = '저기압 기압골이 이 지역에 불안정하고 비 오는 날씨를 가져왔어요.', example_en_3 = 'Meteorologists identified a trough in the upper atmosphere influencing surface weather.', example_ko_3 = '기상학자들이 지상 날씨에 영향을 미치는 상층 대기의 기압골을 확인했어요.', example_en_4 = 'A trough is an elongated area of low atmospheric pressure between two ridges.', example_ko_4 = '기압골은 두 능선 사이의 대기압이 낮은 길게 뻗은 지역이에요.', example_en_5 = 'The trough will deepen overnight, increasing the risk of heavy rainfall.', example_ko_5 = '기압골이 밤사이 깊어지면서 폭우의 위험이 높아질 거예요.' WHERE id = 'w_weather_B1_33';
UPDATE words SET example_en_2 = 'A ridge of high pressure is keeping conditions dry and settled across the country.', example_ko_2 = '고기압 능선이 전국에 걸쳐 건조하고 안정된 상태를 유지시키고 있어요.', example_en_3 = 'The ridge will break down by the weekend, allowing rain to move in from the west.', example_ko_3 = '주말쯤에 능선이 무너지면서 서쪽에서 비가 유입될 거예요.', example_en_4 = 'A strong ridge over the continent is blocking Atlantic weather systems from moving east.', example_ko_4 = '대륙 위의 강한 능선이 대서양 기상 시스템이 동쪽으로 이동하는 것을 막고 있어요.', example_en_5 = 'The persistence of the ridge is responsible for the prolonged dry spell we are experiencing.', example_ko_5 = '능선의 지속성이 우리가 경험하는 장기간의 건조 기간의 원인이에요.' WHERE id = 'w_weather_B1_34';
UPDATE words SET example_en_2 = 'Seasonal allergies affect millions of people every spring and autumn.', example_ko_2 = '계절성 알레르기는 매년 봄과 가을에 수백만 명에게 영향을 미쳐요.', example_en_3 = 'Seasonal changes in weather can affect your mood and energy levels.', example_ko_3 = '날씨의 계절적 변화는 기분과 에너지 수준에 영향을 미칠 수 있어요.', example_en_4 = 'The seasonal migration of birds is triggered by changes in temperature and daylight.', example_ko_4 = '조류의 계절적 이동은 기온과 낮의 길이 변화에 의해 촉발돼요.', example_en_5 = 'A good wardrobe plan accounts for seasonal temperature variations throughout the year.', example_ko_5 = '좋은 옷장 계획은 일 년 동안의 계절적 기온 변화를 고려해요.' WHERE id = 'w_weather_B1_35';
UPDATE words SET example_en_2 = 'Meteorology has advanced significantly with the advent of satellite technology.', example_ko_2 = '위성 기술의 등장으로 기상학이 크게 발전했어요.', example_en_3 = 'A career in meteorology requires a strong background in mathematics and physics.', example_ko_3 = '기상학 분야의 직업을 갖기 위해서는 수학과 물리학에 대한 탄탄한 기초가 필요해요.', example_en_4 = 'Meteorology enables forecasters to predict weather patterns up to two weeks in advance.', example_ko_4 = '기상학은 예보관들이 2주 전까지 날씨 패턴을 예측할 수 있게 해요.', example_en_5 = 'The field of meteorology plays a critical role in aviation safety.', example_ko_5 = '기상학 분야는 항공 안전에 중요한 역할을 해요.' WHERE id = 'w_weather_B2_01';
UPDATE words SET example_en_2 = 'Atmospheric carbon dioxide concentrations have risen to record levels.', example_ko_2 = '대기 중 이산화탄소 농도가 기록적인 수준으로 상승했어요.', example_en_3 = 'Atmospheric pressure decreases as altitude increases.', example_ko_3 = '대기압은 고도가 높아질수록 낮아져요.', example_en_4 = 'Atmospheric scientists study how gases, aerosols, and clouds interact.', example_ko_4 = '대기 과학자들은 가스, 에어로졸, 구름이 어떻게 상호작용하는지 연구해요.', example_en_5 = 'The atmospheric conditions at the time of the eruption contributed to the extent of ash dispersal.', example_ko_5 = '분화 당시의 대기 조건이 화산재 분산 범위에 영향을 미쳤어요.' WHERE id = 'w_weather_B2_02';
UPDATE words SET example_en_2 = 'A cyclone with wind speeds over 250 kilometres per hour struck the coast last night.', example_ko_2 = '어젯밤 시속 250킬로미터 이상의 풍속을 가진 사이클론이 해안을 강타했어요.', example_en_3 = 'Cyclones form over warm tropical oceans and weaken as they move over land.', example_ko_3 = '사이클론은 따뜻한 열대 바다 위에서 형성되고 육지로 이동하면서 약해져요.', example_en_4 = 'The evacuation order was issued 48 hours before the cyclone made landfall.', example_ko_4 = '사이클론이 상륙하기 48시간 전에 대피 명령이 내려졌어요.', example_en_5 = 'Tropical cyclones are known by different names — hurricane, typhoon, or cyclone — depending on their location.', example_ko_5 = '열대 사이클론은 위치에 따라 허리케인, 태풍 또는 사이클론으로 불려요.' WHERE id = 'w_weather_B2_03';
UPDATE words SET example_en_2 = 'The monsoon brought relief from the scorching heat but also severe flooding.', example_ko_2 = '몬순이 뜨거운 더위를 해소해 주었지만 심각한 홍수도 가져왔어요.', example_en_3 = 'Farmers in South Asia depend on the monsoon for their annual rice harvest.', example_ko_3 = '남아시아 농부들은 연간 벼 수확을 위해 몬순에 의존해요.', example_en_4 = 'The delayed monsoon resulted in a severe water shortage across the region.', example_ko_4 = '몬순이 지연되면서 지역 전반에 심각한 물 부족이 발생했어요.', example_en_5 = 'The Asian monsoon is one of the largest and most complex weather systems on Earth.', example_ko_5 = '아시아 몬순은 지구에서 가장 크고 복잡한 기상 시스템 중 하나예요.' WHERE id = 'w_weather_B2_04';
UPDATE words SET example_en_2 = 'Arid regions receive less than 250 millimetres of rainfall per year.', example_ko_2 = '건조 지역은 연간 250밀리미터 미만의 강우량을 받아요.', example_en_3 = 'Specially adapted plants and animals survive in arid desert environments.', example_ko_3 = '특별히 적응한 식물과 동물들이 건조한 사막 환경에서 생존해요.', example_en_4 = 'Water management is a critical challenge in arid and semi-arid countries.', example_ko_4 = '물 관리는 건조하고 반건조한 국가에서 매우 중요한 과제예요.', example_en_5 = 'The arid landscape of the Australian Outback stretches for thousands of kilometres.', example_ko_5 = '호주 아웃백의 건조한 경관이 수천 킬로미터에 걸쳐 펼쳐져 있어요.' WHERE id = 'w_weather_B2_05';
UPDATE words SET example_en_2 = 'Seoul''s subtropical summer is characterised by intense heat and high humidity.', example_ko_2 = '서울의 아열대성 여름은 강렬한 더위와 높은 습도가 특징이에요.', example_en_3 = 'Subtropical regions generally experience warm winters and hot, humid summers.', example_ko_3 = '아열대 지역은 일반적으로 따뜻한 겨울과 덥고 습한 여름을 경험해요.', example_en_4 = 'As the climate warms, subtropical weather patterns are expanding poleward.', example_ko_4 = '기후가 따뜻해지면서 아열대 기상 패턴이 극 방향으로 확장되고 있어요.', example_en_5 = 'The subtropical jet stream influences weather across the northern hemisphere.', example_ko_5 = '아열대 제트 기류는 북반구 전역의 날씨에 영향을 미쳐요.' WHERE id = 'w_weather_B2_06';
UPDATE words SET example_en_2 = 'Barometric pressure fell sharply, signalling the approach of severe weather.', example_ko_2 = '기압이 급격히 떨어지면서 악기상의 접근을 알렸어요.', example_en_3 = 'Barometric readings are used alongside temperature and humidity to produce weather forecasts.', example_ko_3 = '기압 수치는 날씨 예보를 작성하기 위해 온도 및 습도와 함께 사용돼요.', example_en_4 = 'A rising barometric pressure typically indicates improving weather conditions.', example_ko_4 = '기압이 오르면 보통 날씨 상태가 개선되고 있다는 신호예요.', example_en_5 = 'The barometric pressure trend over 24 hours can be a good predictor of tomorrow''s weather.', example_ko_5 = '24시간 동안의 기압 추이는 내일 날씨를 잘 예측할 수 있어요.' WHERE id = 'w_weather_B2_07';
UPDATE words SET example_en_2 = 'The pressure gradient between the two weather systems was driving strong winds.', example_ko_2 = '두 기상 시스템 사이의 기압 경도가 강한 바람을 일으키고 있었어요.', example_en_3 = 'A steep temperature gradient across the front triggered intense thunderstorms.', example_ko_3 = '전선을 가로지르는 가파른 기온 경도가 강한 뇌우를 촉발했어요.', example_en_4 = 'Gradients in atmospheric pressure determine wind speed and direction.', example_ko_4 = '대기압의 경도가 풍속과 바람 방향을 결정해요.', example_en_5 = 'The horizontal temperature gradient between the equator and the poles drives global circulation.', example_ko_5 = '적도와 극지방 사이의 수평 기온 경도가 전 지구적 순환을 유도해요.' WHERE id = 'w_weather_B2_08';
UPDATE words SET example_en_2 = 'The El Niño phenomenon disrupts normal weather patterns across the Pacific.', example_ko_2 = '엘니뇨 현상은 태평양 전역의 정상적인 날씨 패턴을 교란시켜요.', example_en_3 = 'Extreme rainfall events are natural phenomena but are becoming more frequent.', example_ko_3 = '극단적인 강우 사태는 자연 현상이지만 더욱 자주 발생하고 있어요.', example_en_4 = 'The phenomenon of urban heat islands raises city temperatures well above rural areas.', example_ko_4 = '도시 열섬 현상이 도시 기온을 농촌 지역보다 훨씬 높게 만들어요.', example_en_5 = 'Scientists are studying the phenomenon of rapidly intensifying tropical cyclones.', example_ko_5 = '과학자들은 빠르게 강화되는 열대 사이클론 현상을 연구하고 있어요.' WHERE id = 'w_weather_B2_09';
UPDATE words SET example_en_2 = 'Climate projections suggest average global temperatures will rise by two degrees this century.', example_ko_2 = '기후 전망에 따르면 이번 세기에 지구 평균 기온이 2도 상승할 거예요.', example_en_3 = 'The local climate determines which crops can be grown in an area.', example_ko_3 = '지역 기후가 그 지역에서 어떤 작물을 재배할 수 있는지를 결정해요.', example_en_4 = 'Scientists distinguish between weather, which is short-term, and climate, which is long-term.', example_ko_4 = '과학자들은 단기적인 날씨와 장기적인 기후를 구분해요.', example_en_5 = 'The climate of Iceland is surprisingly mild given its northern latitude.', example_ko_5 = '아이슬란드의 기후는 북위를 고려했을 때 놀라울 만큼 온화해요.' WHERE id = 'w_weather_B2_10';
UPDATE words SET example_en_2 = 'The precipitation pattern in this region has shifted significantly over the past fifty years.', example_ko_2 = '이 지역의 강수 패턴이 지난 50년 동안 크게 변화했어요.', example_en_3 = 'Changes in precipitation patterns are disrupting agriculture in many parts of the world.', example_ko_3 = '강수 패턴의 변화가 세계 여러 지역에서 농업을 방해하고 있어요.', example_en_4 = 'Climate models project shifts in precipitation patterns across all continents.', example_ko_4 = '기후 모델은 모든 대륙에 걸쳐 강수 패턴의 변화를 예측해요.', example_en_5 = 'Understanding historical precipitation patterns is essential for predicting future droughts.', example_ko_5 = '과거 강수 패턴을 이해하는 것은 미래 가뭄을 예측하는 데 필수적이에요.' WHERE id = 'w_weather_B2_11';
UPDATE words SET example_en_2 = 'A high pressure system settled over the country, bringing a prolonged dry spell.', example_ko_2 = '나라 위에 고기압 시스템이 자리 잡으면서 장기간의 건조 기간을 가져왔어요.', example_en_3 = 'The high pressure system blocked rain-bearing fronts from moving in from the Atlantic.', example_ko_3 = '고기압 시스템이 대서양에서 유입되는 비를 동반한 전선을 차단했어요.', example_en_4 = 'Persistent high pressure systems can lead to drought conditions in summer.', example_ko_4 = '지속적인 고기압 시스템은 여름에 가뭄 상태로 이어질 수 있어요.', example_en_5 = 'Under a high pressure system, skies are typically clear and winds are light.', example_ko_5 = '고기압 시스템 아래에서는 보통 하늘이 맑고 바람이 약해요.' WHERE id = 'w_weather_B2_12';
UPDATE words SET example_en_2 = 'The low pressure system deepened overnight and brought severe gale-force winds.', example_ko_2 = '저기압 시스템이 밤사이 깊어지면서 심한 강풍을 가져왔어요.', example_en_3 = 'A low pressure system is associated with cloudy, wet, and windy weather.', example_ko_3 = '저기압 시스템은 흐리고 비 오며 바람 부는 날씨와 관련이 있어요.', example_en_4 = 'The low pressure system moved northeast, dragging cold Arctic air behind it.', example_ko_4 = '저기압 시스템이 북동쪽으로 이동하면서 차가운 북극 공기를 끌고 왔어요.', example_en_5 = 'Meteorologists track the development and movement of low pressure systems daily.', example_ko_5 = '기상학자들은 매일 저기압 시스템의 발달과 이동을 추적해요.' WHERE id = 'w_weather_B2_13';
UPDATE words SET example_en_2 = 'Typhoon Hinnamnor was the strongest typhoon to hit the Korean peninsula in decades.', example_ko_2 = '태풍 힌남노는 수십 년 만에 한반도를 강타한 가장 강력한 태풍이었어요.', example_en_3 = 'The typhoon season in East Asia typically runs from June to October.', example_ko_3 = '동아시아의 태풍 철은 보통 6월부터 10월까지예요.', example_en_4 = 'Residents along the coast were evacuated before the typhoon made landfall.', example_ko_4 = '태풍이 상륙하기 전에 해안가 주민들이 대피했어요.', example_en_5 = 'The typhoon caused an estimated five billion dollars worth of damage.', example_ko_5 = '태풍으로 약 50억 달러의 피해가 발생한 것으로 추정돼요.' WHERE id = 'w_weather_B2_14';
UPDATE words SET example_en_2 = 'The intertropical convergence zone migrates northward during the northern hemisphere summer.', example_ko_2 = '열대 수렴대는 북반구 여름 동안 북쪽으로 이동해요.', example_en_3 = 'Rainfall in the tropics is heavily influenced by the position of the intertropical convergence zone.', example_ko_3 = '열대 지역의 강우는 열대 수렴대의 위치에 크게 영향을 받아요.', example_en_4 = 'The intertropical convergence zone is a band of low pressure and heavy rainfall near the equator.', example_ko_4 = '열대 수렴대는 적도 근처의 저기압과 폭우의 띠예요.', example_en_5 = 'Shifts in the intertropical convergence zone can trigger droughts and floods in adjacent regions.', example_ko_5 = '열대 수렴대의 이동이 인접 지역에서 가뭄과 홍수를 촉발할 수 있어요.' WHERE id = 'w_weather_B2_15';
UPDATE words SET example_en_2 = 'Convection is the process by which warm air rises and cool air descends.', example_ko_2 = '대류는 따뜻한 공기가 상승하고 차가운 공기가 내려오는 과정이에요.', example_en_3 = 'Deep convection in the tropics generates the towering cumulonimbus clouds associated with thunderstorms.', example_ko_3 = '열대 지역의 깊은 대류가 뇌우와 관련된 거대한 적란운을 만들어 내요.', example_en_4 = 'Convection in the ocean also helps distribute heat from the tropics to the poles.', example_ko_4 = '해양 대류 역시 열대 지방에서 극지방으로 열을 분배하는 데 도움이 돼요.', example_en_5 = 'On a hot summer afternoon, convection can rapidly build thunderstorms within hours.', example_ko_5 = '더운 여름 오후에는 대류가 몇 시간 내에 빠르게 뇌우를 형성할 수 있어요.' WHERE id = 'w_weather_B2_16';
UPDATE words SET example_en_2 = 'The jet stream steers weather systems across the northern hemisphere.', example_ko_2 = '제트 기류는 북반구 전역의 기상 시스템을 이끌어요.', example_en_3 = 'Disruptions to the jet stream can cause prolonged cold spells or heatwaves.', example_ko_3 = '제트 기류의 교란은 장기간의 한파나 폭염을 유발할 수 있어요.', example_en_4 = 'Aeroplanes flying from west to east often use the jet stream to save fuel.', example_ko_4 = '서쪽에서 동쪽으로 비행하는 비행기들은 연료를 절약하기 위해 제트 기류를 활용해요.', example_en_5 = 'The polar jet stream has been unusually wavy this winter, bringing extreme temperatures.', example_ko_5 = '이번 겨울 극지 제트 기류가 유난히 굴곡져서 극단적인 기온을 가져왔어요.' WHERE id = 'w_weather_B2_17';
UPDATE words SET example_en_2 = 'The trade winds blow consistently from the northeast in the northern tropics.', example_ko_2 = '북부 열대 지역에서는 무역풍이 북동쪽에서 지속적으로 불어요.', example_en_3 = 'Historical sailors relied on the trade winds to navigate across the Atlantic Ocean.', example_ko_3 = '역사적으로 선원들은 대서양을 항해하기 위해 무역풍에 의존했어요.', example_en_4 = 'The weakening of the trade winds during El Niño disrupts weather globally.', example_ko_4 = '엘니뇨 동안 무역풍의 약화가 전 세계 날씨를 교란시켜요.', example_en_5 = 'Trade winds carry moisture from the ocean to tropical islands, sustaining their ecosystems.', example_ko_5 = '무역풍이 바다에서 열대 섬으로 수분을 운반해 생태계를 유지시켜요.' WHERE id = 'w_weather_B2_18';
UPDATE words SET example_en_2 = 'The humidity index today indicates conditions that feel oppressively uncomfortable.', example_ko_2 = '오늘 습도 지수는 매우 불쾌할 정도로 느껴지는 상태를 나타내요.', example_en_3 = 'A high humidity index often coincides with stagnant air and poor ventilation.', example_ko_3 = '높은 습도 지수는 종종 정체된 공기와 열악한 환기와 맞물려요.', example_en_4 = 'The humidity index is widely used in public health warnings during summer.', example_ko_4 = '습도 지수는 여름 동안 공중 보건 경고에 널리 사용돼요.', example_en_5 = 'Workers in outdoor industries monitor the humidity index to manage heat-related risk.', example_ko_5 = '야외 산업 종사자들은 열 관련 위험을 관리하기 위해 습도 지수를 모니터링해요.' WHERE id = 'w_weather_B2_19';
UPDATE words SET example_en_2 = 'The polar vortex collapsed, sending frigid Arctic air deep into North America.', example_ko_2 = '극소용돌이가 붕괴되면서 차가운 북극 공기가 북아메리카 깊숙이 유입됐어요.', example_en_3 = 'A weakened polar vortex is increasingly linked to extreme winter weather events.', example_ko_3 = '약화된 극소용돌이가 극단적인 겨울 기상 현상과 점점 더 연관되고 있어요.', example_en_4 = 'The polar vortex disruption of 2019 caused record cold temperatures across the US Midwest.', example_ko_4 = '2019년의 극소용돌이 교란으로 미국 중서부 전역에 기록적인 한파가 발생했어요.', example_en_5 = 'Scientists are studying whether climate change is making polar vortex disruptions more frequent.', example_ko_5 = '과학자들은 기후 변화가 극소용돌이 교란을 더 자주 만드는지 연구하고 있어요.' WHERE id = 'w_weather_B2_20';
UPDATE words SET example_en_2 = 'The heat dome trapped hot air over the region for nearly two weeks.', example_ko_2 = '열돔이 거의 2주 동안 그 지역 위에 뜨거운 공기를 가두었어요.', example_en_3 = 'The 2021 heat dome over the Pacific Northwest killed hundreds of people.', example_ko_3 = '2021년 태평양 북서부의 열돔으로 수백 명이 사망했어요.', example_en_4 = 'A heat dome forms when a high pressure system stalls and traps heat below it.', example_ko_4 = '열돔은 고기압 시스템이 정체되어 그 아래 열을 가둘 때 형성돼요.', example_en_5 = 'Climate scientists warn that heat domes will become more frequent and intense.', example_ko_5 = '기후 과학자들은 열돔이 더 자주, 더 강하게 발생할 것이라고 경고해요.' WHERE id = 'w_weather_B2_21';
UPDATE words SET example_en_2 = 'Wind shear is one of the main factors that prevents tropical storms from intensifying.', example_ko_2 = '윈드시어는 열대 폭풍이 강화되는 것을 막는 주요 요인 중 하나예요.', example_en_3 = 'Strong wind shear in the upper atmosphere can tear apart developing hurricanes.', example_ko_3 = '상층 대기의 강한 윈드시어가 발달 중인 허리케인을 분열시킬 수 있어요.', example_en_4 = 'Pilots are trained to manage the challenges of wind shear during take-off and landing.', example_ko_4 = '조종사들은 이착륙 중 윈드시어의 어려움을 관리하는 훈련을 받아요.', example_en_5 = 'Wind shear is the change in wind speed or direction over a relatively short distance.', example_ko_5 = '윈드시어는 비교적 짧은 거리에 걸친 풍속이나 풍향의 변화예요.' WHERE id = 'w_weather_B2_22';
UPDATE words SET example_en_2 = 'Evapotranspiration rates are highest during hot, dry, and windy conditions.', example_ko_2 = '증발산율은 덥고 건조하며 바람 부는 조건에서 가장 높아요.', example_en_3 = 'Measuring evapotranspiration helps farmers determine how much irrigation their crops need.', example_ko_3 = '증발산을 측정하면 농부들이 농작물에 필요한 관개량을 결정하는 데 도움이 돼요.', example_en_4 = 'Evapotranspiration combines evaporation from soil and transpiration from plants.', example_ko_4 = '증발산은 토양에서의 증발과 식물에서의 증산을 합친 것이에요.', example_en_5 = 'Climate change is expected to increase evapotranspiration, intensifying drought stress.', example_ko_5 = '기후 변화로 증발산이 증가하여 가뭄 스트레스가 강화될 것으로 예상돼요.' WHERE id = 'w_weather_B2_23';
UPDATE words SET example_en_2 = 'The cold air mass moving south from Canada brought a sharp drop in temperatures.', example_ko_2 = '캐나다에서 남쪽으로 이동하는 차가운 기단이 기온의 급격한 하락을 가져왔어요.', example_en_3 = 'When two contrasting air masses meet, the result is often a weather front.', example_ko_3 = '두 개의 대조적인 기단이 만나면 종종 기상 전선이 형성돼요.', example_en_4 = 'The warm, humid air mass from the Gulf of Mexico fuelled the thunderstorm outbreak.', example_ko_4 = '멕시코만에서 오는 따뜻하고 습한 기단이 뇌우 발생을 부추겼어요.', example_en_5 = 'Air mass characteristics are determined by the surface over which they form.', example_ko_5 = '기단의 특성은 그것이 형성되는 표면에 의해 결정돼요.' WHERE id = 'w_weather_B2_24';
UPDATE words SET example_en_2 = 'A squall line moved through the area bringing heavy rain and gusty winds.', example_ko_2 = '스콜 라인이 지역을 통과하면서 폭우와 돌풍을 가져왔어요.', example_en_3 = 'Sailors must watch for squalls which can develop rapidly with little warning.', example_ko_3 = '선원들은 경고 없이 빠르게 발달할 수 있는 스콜을 주의해야 해요.', example_en_4 = 'The sudden squall caught us off guard as we were halfway across the lake.', example_ko_4 = '호수를 절반쯤 건넜을 때 갑작스러운 스콜에 불시에 당했어요.', example_en_5 = 'A squall is characterised by a sudden, short-lived burst of strong wind and rain.', example_ko_5 = '스콜은 갑작스럽고 단기간의 강풍과 비의 돌풍이 특징이에요.' WHERE id = 'w_weather_B2_25';
UPDATE words SET example_en_2 = 'The valley created its own microclimate, staying warmer than the surrounding hillsides.', example_ko_2 = '계곡이 자체적인 미기후를 만들어 주변 언덕보다 더 따뜻하게 유지됐어요.', example_en_3 = 'Cities create their own microclimate known as the urban heat island effect.', example_ko_3 = '도시는 도시 열섬 효과로 알려진 자체 미기후를 만들어요.', example_en_4 = 'Wine growers carefully select sites based on the microclimate of different slopes.', example_ko_4 = '와인 재배자들은 다양한 경사면의 미기후를 바탕으로 부지를 신중하게 선택해요.', example_en_5 = 'A garden pond can create a slightly more humid microclimate in its immediate surroundings.', example_ko_5 = '정원 연못은 바로 주변에 약간 더 습한 미기후를 만들 수 있어요.' WHERE id = 'w_weather_B2_26';
UPDATE words SET example_en_2 = 'The atmosphere is a thin layer of gases that surrounds the Earth and supports life.', example_ko_2 = '대기는 지구를 둘러싸고 생명을 지탱하는 얇은 가스층이에요.', example_en_3 = 'Pollutants released into the atmosphere can travel thousands of kilometres.', example_ko_3 = '대기 중으로 방출된 오염 물질은 수천 킬로미터를 이동할 수 있어요.', example_en_4 = 'The upper layers of the atmosphere absorb harmful ultraviolet radiation from the sun.', example_ko_4 = '대기의 상층은 태양에서 오는 유해한 자외선을 흡수해요.', example_en_5 = 'The composition of Earth''s atmosphere is dominated by nitrogen and oxygen.', example_ko_5 = '지구 대기의 성분은 질소와 산소가 지배적이에요.' WHERE id = 'w_weather_B2_27';
UPDATE words SET example_en_2 = 'The temperature anomaly last July was the largest on record globally.', example_ko_2 = '지난 7월 기온 편차가 전 세계적으로 기록상 가장 컸어요.', example_en_3 = 'Scientists use temperature anomalies relative to a baseline period to track warming.', example_ko_3 = '과학자들은 온난화를 추적하기 위해 기준 기간 대비 기온 편차를 사용해요.', example_en_4 = 'A temperature anomaly of plus 1.5 degrees above pre-industrial levels is a key climate threshold.', example_ko_4 = '산업화 이전 수준보다 +1.5도의 기온 편차는 핵심 기후 임계값이에요.', example_en_5 = 'Regional temperature anomalies can be much larger than the global average figure suggests.', example_ko_5 = '지역 기온 편차는 전 세계 평균 수치가 나타내는 것보다 훨씬 클 수 있어요.' WHERE id = 'w_weather_B2_28';
UPDATE words SET example_en_2 = 'Condensation on cold surfaces occurs when warm, moist air contacts them.', example_ko_2 = '따뜻하고 습한 공기가 차가운 표면에 닿을 때 결로가 발생해요.', example_en_3 = 'Condensation in the atmosphere is the process that forms clouds and precipitation.', example_ko_3 = '대기 중의 응결은 구름과 강수를 형성하는 과정이에요.', example_en_4 = 'The glass of cold water was covered in condensation on the humid summer day.', example_ko_4 = '습한 여름날 차가운 물이 든 유리컵 표면이 결로로 뒤덮였어요.', example_en_5 = 'Dew forms through the condensation of water vapour on surfaces that have cooled overnight.', example_ko_5 = '이슬은 밤새 식은 표면에서 수증기가 응결되어 형성돼요.' WHERE id = 'w_weather_B2_29';
UPDATE words SET example_en_2 = 'Evaporation from the ocean surface is the primary source of atmospheric moisture.', example_ko_2 = '해양 표면에서의 증발이 대기 수분의 주요 공급원이에요.', example_en_3 = 'High temperatures accelerate evaporation, which can intensify drought conditions.', example_ko_3 = '고온이 증발을 가속화하여 가뭄 상태를 심화시킬 수 있어요.', example_en_4 = 'Evaporation cools the surface from which it occurs, which is why sweating helps cool us down.', example_ko_4 = '증발은 발생하는 표면을 냉각시키는데, 이것이 땀이 우리를 식히는 이유예요.', example_en_5 = 'Evaporation from reservoirs can account for a significant loss of stored water in arid regions.', example_ko_5 = '건조 지역에서는 저수지에서의 증발이 저장된 물의 상당한 손실을 차지할 수 있어요.' WHERE id = 'w_weather_B2_30';
UPDATE words SET example_en_2 = 'Cloud seeding involves dispersing substances into clouds to encourage precipitation.', example_ko_2 = '구름씨뿌리기는 강수를 유도하기 위해 구름에 물질을 분산시키는 작업을 포함해요.', example_en_3 = 'Several countries use cloud seeding to increase rainfall in drought-prone regions.', example_ko_3 = '여러 나라가 가뭄에 취약한 지역에서 강우량을 늘리기 위해 구름씨뿌리기를 사용해요.', example_en_4 = 'Cloud seeding typically uses silver iodide particles to trigger ice crystal formation.', example_ko_4 = '구름씨뿌리기는 보통 얼음 결정 형성을 유도하기 위해 아이오딘화 은 입자를 사용해요.', example_en_5 = 'The effectiveness of cloud seeding remains a subject of ongoing scientific debate.', example_ko_5 = '구름씨뿌리기의 효과는 계속해서 과학적 논쟁의 주제로 남아 있어요.' WHERE id = 'w_weather_B2_31';
UPDATE words SET example_en_2 = 'Isobars on a weather map connect points of equal atmospheric pressure.', example_ko_2 = '날씨 지도의 등압선은 같은 대기압을 가진 지점들을 연결해요.', example_en_3 = 'Closely spaced isobars indicate strong pressure gradients and high wind speeds.', example_ko_3 = '촘촘한 등압선은 강한 기압 경도와 높은 풍속을 나타내요.', example_en_4 = 'Meteorologists analyse isobars to determine the direction and speed of approaching weather systems.', example_ko_4 = '기상학자들은 접근하는 기상 시스템의 방향과 속도를 결정하기 위해 등압선을 분석해요.', example_en_5 = 'Reading isobars is a fundamental skill in understanding surface weather charts.', example_ko_5 = '등압선 읽기는 지상 날씨 차트를 이해하는 데 기본적인 기술이에요.' WHERE id = 'w_weather_B2_32';
UPDATE words SET example_en_2 = 'Isotherms on the chart revealed a sharp temperature contrast across the weather front.', example_ko_2 = '차트의 등온선이 기상 전선 전역에 걸쳐 뚜렷한 기온 대비를 드러냈어요.', example_en_3 = 'An isotherm connects all points on a map that share the same temperature.', example_ko_3 = '등온선은 지도에서 같은 기온을 공유하는 모든 지점을 연결해요.', example_en_4 = 'Climate maps often display isotherms to show the distribution of seasonal temperatures.', example_ko_4 = '기후 지도는 종종 계절적 기온 분포를 보여주기 위해 등온선을 표시해요.', example_en_5 = 'The northward shift of isotherms over decades is a visual indicator of global warming.', example_ko_5 = '수십 년에 걸쳐 등온선이 북쪽으로 이동하는 것은 지구 온난화의 시각적 지표예요.' WHERE id = 'w_weather_B2_33';
UPDATE words SET example_en_2 = 'An anticyclone over Scandinavia has been responsible for the warm, dry summer weather.', example_ko_2 = '스칸디나비아 위의 고기압이 따뜻하고 건조한 여름 날씨의 원인이었어요.', example_en_3 = 'An anticyclone brings settled, calm weather with light winds and clear skies.', example_ko_3 = '고기압은 약한 바람과 맑은 하늘의 안정적이고 잔잔한 날씨를 가져와요.', example_en_4 = 'In winter, an anticyclone can trap cold air near the surface, leading to frost and fog.', example_ko_4 = '겨울에 고기압은 차가운 공기를 지표면 근처에 가두어 서리와 안개를 유발할 수 있어요.', example_en_5 = 'The anticyclone finally moved east, allowing Atlantic fronts to bring rain again.', example_ko_5 = '고기압이 마침내 동쪽으로 이동하면서 대서양 전선이 다시 비를 가져올 수 있게 됐어요.' WHERE id = 'w_weather_B2_34';
UPDATE words SET example_en_2 = 'Ocean currents carry heat from the tropics to higher latitudes, moderating the climate.', example_ko_2 = '해류가 열대 지방에서 고위도 지역으로 열을 운반하여 기후를 완화시켜요.', example_en_3 = 'The Gulf Stream is a powerful ocean current that keeps Western Europe mild.', example_ko_3 = '멕시코 만류는 서유럽을 온화하게 유지하는 강력한 해류예요.', example_en_4 = 'Changes in ocean currents can have dramatic effects on regional weather patterns.', example_ko_4 = '해류의 변화는 지역 날씨 패턴에 극적인 영향을 미칠 수 있어요.', example_en_5 = 'The La Niña phenomenon is linked to a strengthening of equatorial ocean currents.', example_ko_5 = '라니냐 현상은 적도 해류의 강화와 연관이 있어요.' WHERE id = 'w_weather_B2_35';
UPDATE words SET example_en_2 = 'Climatology relies on long-term data records spanning decades or centuries.', example_ko_2 = '기후학은 수십 년 또는 수 세기에 걸친 장기 데이터 기록에 의존해요.', example_en_3 = 'Climatology helps us understand how natural and human factors shape the climate.', example_ko_3 = '기후학은 자연적, 인위적 요인이 어떻게 기후를 형성하는지 이해하는 데 도움이 돼요.', example_en_4 = 'Advances in climatology have improved the accuracy of long-range climate projections.', example_ko_4 = '기후학의 발전이 장기 기후 전망의 정확도를 향상시켰어요.', example_en_5 = 'Climatology is a broad discipline that intersects with oceanography, ecology, and atmospheric science.', example_ko_5 = '기후학은 해양학, 생태학, 대기과학과 교차하는 폭넓은 학문이에요.' WHERE id = 'w_weather_C1_01';
UPDATE words SET example_en_2 = 'The microclimate within the forest was significantly cooler than the surrounding farmland.', example_ko_2 = '숲 안의 미기후는 주변 농지보다 훨씬 서늘했어요.', example_en_3 = 'Urban planners consider microclimate when designing parks and green spaces.', example_ko_3 = '도시 계획자들은 공원과 녹지를 설계할 때 미기후를 고려해요.', example_en_4 = 'The vineyard''s unique microclimate produces grapes with a distinctive flavour profile.', example_ko_4 = '포도밭의 독특한 미기후가 독특한 풍미를 지닌 포도를 생산해요.', example_en_5 = 'Even small features like walls and hedgerows can create their own microclimate.', example_ko_5 = '담장이나 산울타리 같은 작은 특징들도 자체적인 미기후를 만들 수 있어요.' WHERE id = 'w_weather_C1_02';
UPDATE words SET example_en_2 = 'A temperature inversion trapped pollutants near the ground, causing severe smog.', example_ko_2 = '기온 역전이 오염 물질을 지표면 근처에 가두어 심각한 스모그를 유발했어요.', example_en_3 = 'During a temperature inversion, cold air is trapped beneath a layer of warmer air.', example_ko_3 = '기온 역전 동안에는 차가운 공기가 따뜻한 공기층 아래에 갇혀요.', example_en_4 = 'Inversions are common in valleys on calm, clear nights when the ground cools rapidly.', example_ko_4 = '기온 역전은 지면이 빠르게 식는 맑고 잔잔한 밤에 계곡에서 흔해요.', example_en_5 = 'The inversion layer prevented rain clouds from forming despite high surface humidity.', example_ko_5 = '역전층이 높은 지면 습도에도 불구하고 비구름 형성을 방해했어요.' WHERE id = 'w_weather_C1_03';
UPDATE words SET example_en_2 = 'The stratosphere contains the ozone layer which protects life from ultraviolet radiation.', example_ko_2 = '성층권에는 자외선으로부터 생명을 보호하는 오존층이 있어요.', example_en_3 = 'Volcanic eruptions can inject aerosols into the stratosphere, temporarily cooling the planet.', example_ko_3 = '화산 폭발이 에어로졸을 성층권으로 주입하여 일시적으로 지구를 냉각시킬 수 있어요.', example_en_4 = 'Aircraft cruise in the lower stratosphere to avoid the turbulence of the troposphere.', example_ko_4 = '항공기는 대류권의 난기류를 피하기 위해 성층권 하부에서 순항해요.', example_en_5 = 'Stratospheric temperatures increase with altitude due to the absorption of solar radiation.', example_ko_5 = '성층권 기온은 태양 복사 흡수로 인해 고도가 높아질수록 올라가요.' WHERE id = 'w_weather_C1_04';
UPDATE words SET example_en_2 = 'El Niño events can trigger floods in South America and droughts in Australia simultaneously.', example_ko_2 = '엘니뇨 현상은 남아메리카의 홍수와 호주의 가뭄을 동시에 유발할 수 있어요.', example_en_3 = 'The 1997 to 1998 El Niño was one of the strongest and most damaging on record.', example_ko_3 = '1997년부터 1998년까지의 엘니뇨는 기록상 가장 강력하고 피해가 컸던 것 중 하나였어요.', example_en_4 = 'El Niño is characterised by unusually warm sea surface temperatures in the eastern Pacific.', example_ko_4 = '엘니뇨는 동부 태평양의 비정상적으로 따뜻한 해수면 온도가 특징이에요.', example_en_5 = 'Forecasters monitor sea surface temperatures closely to predict the onset of El Niño.', example_ko_5 = '예보관들은 엘니뇨 발생을 예측하기 위해 해수면 온도를 면밀히 모니터링해요.' WHERE id = 'w_weather_C1_05';
UPDATE words SET example_en_2 = 'The statistical anomaly in the temperature record prompted further investigation.', example_ko_2 = '기온 기록의 통계적 이상 현상이 추가 조사를 촉발했어요.', example_en_3 = 'An anomaly in the rainfall data suggested an instrument calibration error.', example_ko_3 = '강수 데이터의 이상 현상이 기기 보정 오류를 시사했어요.', example_en_4 = 'Climate anomalies caused by El Niño can persist for twelve to eighteen months.', example_ko_4 = '엘니뇨로 인한 기후 이상 현상은 12에서 18개월 지속될 수 있어요.', example_en_5 = 'The anomaly was more than three standard deviations above the long-term mean.', example_ko_5 = '그 이상 현상은 장기 평균보다 3 표준 편차 이상 높았어요.' WHERE id = 'w_weather_C1_06';
UPDATE words SET example_en_2 = 'A two-degree deviation from the mean temperature can signal a significant climate shift.', example_ko_2 = '평균 기온에서 2도 편차는 중요한 기후 변화를 신호할 수 있어요.', example_en_3 = 'Any deviation from the forecast temperature should be explained in the meteorological report.', example_ko_3 = '예보 기온에서의 모든 편차는 기상 보고서에 설명되어야 해요.', example_en_4 = 'The deviation of the jet stream from its typical path led to unusual weather across Europe.', example_ko_4 = '제트 기류가 전형적인 경로에서 벗어난 것이 유럽 전역에 이례적인 날씨를 야기했어요.', example_en_5 = 'Scientists measure deviation from the baseline to quantify climate change over time.', example_ko_5 = '과학자들은 시간이 지남에 따라 기후 변화를 정량화하기 위해 기준선에서의 편차를 측정해요.' WHERE id = 'w_weather_C1_07';
UPDATE words SET example_en_2 = 'The UK has a temperate oceanic climate with mild winters and cool summers.', example_ko_2 = '영국은 온화한 겨울과 시원한 여름의 온대 해양성 기후를 가지고 있어요.', example_en_3 = 'Temperate regions experience significant seasonal variation compared to tropical zones.', example_ko_3 = '온대 지역은 열대 지역에 비해 계절 변화가 뚜렷해요.', example_en_4 = 'The temperate climate of New Zealand is ideal for a wide range of agriculture.', example_ko_4 = '뉴질랜드의 온대 기후는 다양한 농업에 이상적이에요.', example_en_5 = 'In temperate climates, spring and autumn are transitional seasons with variable weather.', example_ko_5 = '온대 기후에서는 봄과 가을이 날씨가 변덕스러운 전환의 계절이에요.' WHERE id = 'w_weather_C1_08';
UPDATE words SET example_en_2 = 'An oceanic climate is characterised by frequent rainfall distributed throughout the year.', example_ko_2 = '해양성 기후는 일 년 내내 고르게 분포된 잦은 강수가 특징이에요.', example_en_3 = 'Western Scotland has a strongly oceanic climate due to its exposure to Atlantic systems.', example_ko_3 = '스코틀랜드 서부는 대서양 시스템에 노출되어 강한 해양성 기후를 가지고 있어요.', example_en_4 = 'The oceanic influence of the Gulf Stream keeps Ireland''s winters remarkably mild.', example_ko_4 = '멕시코 만류의 해양 영향이 아일랜드의 겨울을 놀라울 만큼 온화하게 유지해요.', example_en_5 = 'Plants in oceanic climates rarely experience the extremes of frost common in continental interiors.', example_ko_5 = '해양성 기후의 식물들은 대륙 내부에서 흔한 극단적인 서리를 거의 경험하지 않아요.' WHERE id = 'w_weather_C1_09';
UPDATE words SET example_en_2 = 'A continental climate has large temperature swings between summer and winter.', example_ko_2 = '대륙성 기후는 여름과 겨울 사이에 큰 기온 변화가 있어요.', example_en_3 = 'Continental interiors receive far less rainfall than coastal regions.', example_ko_3 = '대륙 내부는 해안 지역보다 강우량이 훨씬 적어요.', example_en_4 = 'Moscow has a strongly continental climate with very cold winters and warm summers.', example_ko_4 = '모스크바는 매우 추운 겨울과 따뜻한 여름의 강한 대륙성 기후를 가지고 있어요.', example_en_5 = 'The continental climate of the Canadian prairies supports vast wheat fields.', example_ko_5 = '캐나다 대평원의 대륙성 기후가 광대한 밀밭을 지탱해요.' WHERE id = 'w_weather_C1_10';
UPDATE words SET example_en_2 = 'A weakening of the thermohaline circulation could disrupt the climate of Northwestern Europe.', example_ko_2 = '열염 순환의 약화가 북서 유럽의 기후를 교란시킬 수 있어요.', example_en_3 = 'The thermohaline circulation is often described as the ocean''s global conveyor belt.', example_ko_3 = '열염 순환은 흔히 해양의 전 지구적 컨베이어 벨트로 묘사돼요.', example_en_4 = 'Fresh water from melting ice sheets could slow down the thermohaline circulation.', example_ko_4 = '녹는 빙상에서 나오는 담수가 열염 순환을 늦출 수 있어요.', example_en_5 = 'The thermohaline circulation transports both heat and nutrients across ocean basins.', example_ko_5 = '열염 순환은 해양 분지 전체에 걸쳐 열과 영양분을 운반해요.' WHERE id = 'w_weather_C1_11';
UPDATE words SET example_en_2 = 'Snow and ice have high albedo, reflecting most incoming solar radiation back into space.', example_ko_2 = '눈과 얼음은 높은 알베도를 가져서 들어오는 태양 복사의 대부분을 우주로 반사해요.', example_en_3 = 'The loss of Arctic sea ice reduces the albedo of the region, amplifying warming.', example_ko_3 = '북극 해빙 손실이 그 지역의 알베도를 감소시켜 온난화를 증폭시켜요.', example_en_4 = 'Dark forests have a lower albedo than open grasslands, absorbing more solar energy.', example_ko_4 = '어두운 숲은 열린 초원보다 알베도가 낮아서 더 많은 태양 에너지를 흡수해요.', example_en_5 = 'Cloud albedo feedback is a significant source of uncertainty in climate models.', example_ko_5 = '구름 알베도 피드백은 기후 모델에서 불확실성의 중요한 원천이에요.' WHERE id = 'w_weather_C1_12';
UPDATE words SET example_en_2 = 'Greenhouse gases exert a positive radiative forcing that warms the climate.', example_ko_2 = '온실 가스는 기후를 따뜻하게 만드는 양의 복사 강제력을 발휘해요.', example_en_3 = 'Aerosols from volcanic eruptions can impose a negative radiative forcing, causing temporary cooling.', example_ko_3 = '화산 폭발에서 나오는 에어로졸이 음의 복사 강제력을 가하여 일시적 냉각을 일으킬 수 있어요.', example_en_4 = 'The net radiative forcing since the industrial era is strongly positive, driving warming.', example_ko_4 = '산업 시대 이후 순 복사 강제력은 강하게 양수여서 온난화를 유발해요.', example_en_5 = 'Researchers calculate radiative forcing to compare the climate impact of different gases.', example_ko_5 = '연구자들은 다양한 가스의 기후 영향을 비교하기 위해 복사 강제력을 계산해요.' WHERE id = 'w_weather_C1_13';
UPDATE words SET example_en_2 = 'Permafrost covers nearly a quarter of the land surface in the Northern Hemisphere.', example_ko_2 = '영구 동토층은 북반구 육지 표면의 거의 4분의 1을 덮고 있어요.', example_en_3 = 'Thawing permafrost releases methane, a potent greenhouse gas, into the atmosphere.', example_ko_3 = '해동되는 영구 동토층이 강력한 온실 가스인 메탄을 대기 중으로 방출해요.', example_en_4 = 'Infrastructure in Arctic regions is being damaged as permafrost thaws.', example_ko_4 = '영구 동토층이 해동되면서 북극 지역의 인프라가 손상되고 있어요.', example_en_5 = 'The rate of permafrost thaw is accelerating faster than many models had projected.', example_ko_5 = '영구 동토층 해동 속도가 많은 모델이 예측한 것보다 빠르게 가속되고 있어요.' WHERE id = 'w_weather_C1_14';
UPDATE words SET example_en_2 = 'Scientists warn that some climate tipping points may already have been crossed.', example_ko_2 = '과학자들은 일부 기후 티핑 포인트가 이미 넘어섰을 수 있다고 경고해요.', example_en_3 = 'The collapse of the West Antarctic Ice Sheet is considered a major climate tipping point.', example_ko_3 = '서남극 빙상의 붕괴는 주요 기후 티핑 포인트로 간주돼요.', example_en_4 = 'Crossing a tipping point can trigger irreversible and self-reinforcing changes to the climate.', example_ko_4 = '티핑 포인트를 넘으면 기후에 비가역적이고 자기 강화적인 변화를 촉발할 수 있어요.', example_en_5 = 'Researchers have identified at least fifteen potential climate tipping points globally.', example_ko_5 = '연구자들은 전 세계적으로 최소 15개의 잠재적 기후 티핑 포인트를 확인했어요.' WHERE id = 'w_weather_C1_15';
UPDATE words SET example_en_2 = 'Aerosols in the atmosphere can both scatter and absorb solar radiation.', example_ko_2 = '대기 중의 에어로졸은 태양 복사를 산란시키고 흡수할 수 있어요.', example_en_3 = 'Black carbon aerosols absorb sunlight and contribute to warming the atmosphere.', example_ko_3 = '블랙 카본 에어로졸은 햇빛을 흡수하여 대기 온난화에 기여해요.', example_en_4 = 'Sulphate aerosols from industrial emissions have a net cooling effect on the climate.', example_ko_4 = '산업 배출의 황산염 에어로졸은 기후에 순 냉각 효과를 가져요.', example_en_5 = 'The 1991 Mount Pinatubo eruption injected massive amounts of aerosols into the stratosphere.', example_ko_5 = '1991년 피나투보 산 분화가 대량의 에어로졸을 성층권으로 주입했어요.' WHERE id = 'w_weather_C1_16';
UPDATE words SET example_en_2 = 'Meridional flow allows cold Arctic air to penetrate deep into the mid-latitudes.', example_ko_2 = '경선 방향 흐름이 차가운 북극 공기가 중위도 깊숙이 침투하게 해요.', example_en_3 = 'An amplified meridional flow pattern is associated with blocking and persistent weather extremes.', example_ko_3 = '증폭된 경선 방향 흐름 패턴은 블로킹 현상 및 지속적인 기상 극단과 관련이 있어요.', example_en_4 = 'Strong meridional flow can bring both heatwaves to some areas and cold snaps to others simultaneously.', example_ko_4 = '강한 경선 방향 흐름은 일부 지역에 폭염을, 다른 지역에 한파를 동시에 가져올 수 있어요.', example_en_5 = 'The shift from zonal to meridional flow is a key driver of mid-latitude weather variability.', example_ko_5 = '대기 흐름이 동서 방향에서 경선 방향으로 바뀌는 것이 중위도 날씨 변동성의 핵심 요인이에요.' WHERE id = 'w_weather_C1_17';
UPDATE words SET example_en_2 = 'A strong zonal flow pattern generally keeps cold Arctic air locked in the polar regions.', example_ko_2 = '강한 동서 방향 흐름 패턴은 일반적으로 차가운 북극 공기를 극지방에 가두어요.', example_en_3 = 'During periods of zonal flow, the mid-latitudes experience mild, relatively stable conditions.', example_ko_3 = '동서 방향 흐름 기간 동안 중위도는 온화하고 비교적 안정된 상태를 경험해요.', example_en_4 = 'The shift from zonal to meridional flow brought extreme temperatures to both northern and southern regions.', example_ko_4 = '동서 방향에서 경선 방향으로의 전환이 북부와 남부 지역 모두에 극단적인 기온을 가져왔어요.', example_en_5 = 'Zonal flow indices help climatologists track the large-scale circulation patterns of the atmosphere.', example_ko_5 = '동서 흐름 지수는 기후학자들이 대기의 대규모 순환 패턴을 추적하는 데 도움이 돼요.' WHERE id = 'w_weather_C1_18';
UPDATE words SET example_en_2 = 'The ice-albedo feedback loop accelerates warming by reducing the reflectivity of polar regions.', example_ko_2 = '얼음-알베도 피드백 루프가 극지방의 반사율을 감소시켜 온난화를 가속화해요.', example_en_3 = 'Permafrost thaw initiates a positive feedback loop releasing additional carbon into the atmosphere.', example_ko_3 = '영구 동토층 해동이 대기 중으로 추가 탄소를 방출하는 양의 피드백 루프를 시작해요.', example_en_4 = 'Understanding feedback loops is essential for building accurate climate models.', example_ko_4 = '피드백 루프를 이해하는 것은 정확한 기후 모델을 구축하는 데 필수적이에요.', example_en_5 = 'Negative feedback loops in the climate system help stabilise temperatures over long time scales.', example_ko_5 = '기후 시스템의 음의 피드백 루프는 장기간에 걸쳐 기온을 안정화하는 데 도움이 돼요.' WHERE id = 'w_weather_C1_19';
UPDATE words SET example_en_2 = 'The Montreal Protocol was designed to protect stratospheric ozone from further depletion.', example_ko_2 = '몬트리올 의정서는 성층권 오존을 추가 감소로부터 보호하기 위해 설계됐어요.', example_en_3 = 'Stratospheric ozone absorbs harmful UV-B and UV-C radiation from the sun.', example_ko_3 = '성층권 오존은 태양에서 오는 유해한 UV-B 및 UV-C 복사를 흡수해요.', example_en_4 = 'The recovery of stratospheric ozone is considered one of the great environmental success stories.', example_ko_4 = '성층권 오존의 회복은 위대한 환경 성공 사례 중 하나로 여겨져요.', example_en_5 = 'Chlorofluorocarbons are the primary substances responsible for stratospheric ozone depletion.', example_ko_5 = '염화불화탄소가 성층권 오존 파괴의 주요 원인 물질이에요.' WHERE id = 'w_weather_C1_20';
UPDATE words SET example_en_2 = 'The teleconnection between the Arctic Oscillation and European winters is well documented.', example_ko_2 = '북극 진동과 유럽 겨울 사이의 원격 상관관계는 잘 문서화되어 있어요.', example_en_3 = 'Teleconnections allow weather events in one part of the world to influence conditions elsewhere.', example_ko_3 = '원격 상관관계는 세계 한 지역의 기상 현상이 다른 곳의 상태에 영향을 미치게 해요.', example_en_4 = 'Researchers study teleconnections to improve seasonal climate forecasts globally.', example_ko_4 = '연구자들은 전 세계적으로 계절 기후 예보를 개선하기 위해 원격 상관관계를 연구해요.', example_en_5 = 'The Indian Ocean Dipole is a key teleconnection that affects rainfall across Asia and Africa.', example_ko_5 = '인도양 쌍극자는 아시아와 아프리카 전역의 강수에 영향을 미치는 핵심 원격 상관관계예요.' WHERE id = 'w_weather_C1_21';
UPDATE words SET example_en_2 = 'Heavy rainfall increases surface runoff, raising the risk of flash flooding in urban areas.', example_ko_2 = '폭우가 지표 유출을 증가시켜 도시 지역의 갑작스러운 홍수 위험을 높여요.', example_en_3 = 'Deforestation increases runoff by removing trees that would otherwise absorb rainfall.', example_ko_3 = '삼림 벌채는 강우를 흡수하는 나무를 제거하여 유출을 증가시켜요.', example_en_4 = 'Sustainable drainage systems are designed to slow runoff and reduce flood risk in cities.', example_ko_4 = '지속 가능한 배수 시스템은 도시의 유출을 늦추고 홍수 위험을 줄이기 위해 설계됐어요.', example_en_5 = 'Measuring runoff volumes helps engineers design appropriate flood defences.', example_ko_5 = '유출량을 측정하면 엔지니어들이 적절한 홍수 방어 시설을 설계하는 데 도움이 돼요.' WHERE id = 'w_weather_C1_22';
UPDATE words SET example_en_2 = 'Glacier retreat in the Himalayas threatens the long-term water supply of millions of people.', example_ko_2 = '히말라야의 빙하 후퇴가 수백만 명의 장기적인 물 공급을 위협해요.', example_en_3 = 'Photographic records clearly document the scale of glacier retreat over recent decades.', example_ko_3 = '사진 기록이 최근 수십 년간의 빙하 후퇴 규모를 명확히 기록해요.', example_en_4 = 'The rate of glacier retreat is accelerating as global temperatures rise.', example_ko_4 = '지구 기온이 오르면서 빙하 후퇴 속도가 가속되고 있어요.', example_en_5 = 'Glacier retreat reduces the albedo of the landscape and contributes to further warming.', example_ko_5 = '빙하 후퇴가 경관의 알베도를 줄여 추가 온난화에 기여해요.' WHERE id = 'w_weather_C1_23';
UPDATE words SET example_en_2 = 'Sea level rise threatens low-lying coastal cities and small island nations.', example_ko_2 = '해수면 상승이 저지대 해안 도시와 소규모 도서 국가를 위협해요.', example_en_3 = 'Both thermal expansion of water and melting ice sheets contribute to sea level rise.', example_ko_3 = '물의 열팽창과 빙상 용해 모두 해수면 상승에 기여해요.', example_en_4 = 'Even a modest sea level rise could expose millions of people to annual flooding.', example_ko_4 = '해수면이 약간만 상승해도 수백만 명이 매년 홍수에 노출될 수 있어요.', example_en_5 = 'Adapting coastal infrastructure to sea level rise is a major challenge for urban planners.', example_ko_5 = '해수면 상승에 맞게 해안 인프라를 적응시키는 것은 도시 계획자들에게 큰 과제예요.' WHERE id = 'w_weather_C1_24';
UPDATE words SET example_en_2 = 'The carbon cycle describes how carbon moves between the atmosphere, land, and oceans.', example_ko_2 = '탄소 순환은 탄소가 대기, 육지, 바다 사이를 어떻게 이동하는지 설명해요.', example_en_3 = 'Human activities have disrupted the carbon cycle by releasing fossil carbon into the atmosphere.', example_ko_3 = '인간 활동이 화석 탄소를 대기 중으로 방출함으로써 탄소 순환을 교란시켰어요.', example_en_4 = 'Forests play a vital role in the carbon cycle by absorbing CO₂ through photosynthesis.', example_ko_4 = '숲은 광합성을 통해 CO₂를 흡수함으로써 탄소 순환에서 중요한 역할을 해요.', example_en_5 = 'Understanding the carbon cycle is essential for designing effective climate mitigation strategies.', example_ko_5 = '탄소 순환을 이해하는 것은 효과적인 기후 완화 전략을 설계하는 데 필수적이에요.' WHERE id = 'w_weather_C1_25';
UPDATE words SET example_en_2 = 'The greenhouse effect is a natural process that keeps the Earth warm enough to support life.', example_ko_2 = '온실 효과는 지구를 생명을 지탱할 만큼 따뜻하게 유지하는 자연 과정이에요.', example_en_3 = 'Enhanced greenhouse effect, driven by human emissions, is causing rapid climate change.', example_ko_3 = '인간 배출에 의해 강화된 온실 효과가 급격한 기후 변화를 일으키고 있어요.', example_en_4 = 'Water vapour is actually the most abundant greenhouse gas in the atmosphere.', example_ko_4 = '수증기는 실제로 대기에서 가장 풍부한 온실 가스예요.', example_en_5 = 'Without any greenhouse effect, the average temperature of Earth would be about minus 18 degrees.', example_ko_5 = '온실 효과가 전혀 없다면 지구의 평균 기온은 약 영하 18도가 될 거예요.' WHERE id = 'w_weather_C1_26';
UPDATE words SET example_en_2 = 'ENSO alternates between El Niño warm phases and La Niña cool phases irregularly.', example_ko_2 = 'ENSO는 불규칙하게 엘니뇨 온난 위상과 라니냐 냉각 위상 사이를 번갈아 가요.', example_en_3 = 'ENSO is one of the most important climate drivers at interannual timescales.', example_ko_3 = 'ENSO는 연간 시간 규모에서 가장 중요한 기후 요인 중 하나예요.', example_en_4 = 'Forecasters use ENSO forecasts to predict seasonal rainfall anomalies globally.', example_ko_4 = '예보관들은 전 세계적으로 계절적 강수 이상 현상을 예측하기 위해 ENSO 예보를 사용해요.', example_en_5 = 'ENSO has significant economic impacts on agriculture, fisheries, and water resources worldwide.', example_ko_5 = 'ENSO는 전 세계 농업, 어업, 수자원에 중요한 경제적 영향을 미쳐요.' WHERE id = 'w_weather_C1_27';
UPDATE words SET example_en_2 = 'La Niña is associated with cooler than average sea surface temperatures in the central Pacific.', example_ko_2 = '라니냐는 중앙 태평양의 평균보다 낮은 해수면 온도와 관련이 있어요.', example_en_3 = 'La Niña years often bring increased hurricane activity in the Atlantic basin.', example_ko_3 = '라니냐 해에는 대서양 분지에서 허리케인 활동이 증가하는 경우가 많아요.', example_en_4 = 'During La Niña, Australia and Southeast Asia typically experience above-average rainfall.', example_ko_4 = '라니냐 동안 호주와 동남아시아는 보통 평균 이상의 강수량을 경험해요.', example_en_5 = 'The transition from El Niño to La Niña can occur within a matter of months.', example_ko_5 = '엘니뇨에서 라니냐로의 전환은 몇 달 이내에 발생할 수 있어요.' WHERE id = 'w_weather_C1_28';
UPDATE words SET example_en_2 = 'Storm surge caused severe flooding well inland when the hurricane made landfall.', example_ko_2 = '허리케인이 상륙했을 때 폭풍 해일이 내륙 깊숙이 심각한 홍수를 일으켰어요.', example_en_3 = 'A storm surge is the abnormal rise in sea level generated by a storm''s winds.', example_ko_3 = '폭풍 해일은 폭풍의 바람에 의해 발생하는 비정상적인 해수면 상승이에요.', example_en_4 = 'Coastal barriers can reduce the impact of storm surge on low-lying communities.', example_ko_4 = '해안 방벽은 저지대 지역 사회에 대한 폭풍 해일의 영향을 줄일 수 있어요.', example_en_5 = 'The storm surge from Typhoon Hainan flooded areas up to seven metres above normal sea level.', example_ko_5 = '태풍의 폭풍 해일이 정상 해수면보다 7미터 높은 지역까지 침수시켰어요.' WHERE id = 'w_weather_C1_29';
UPDATE words SET example_en_2 = 'Deep convection over the tropics drives the upward branch of the Hadley circulation.', example_ko_2 = '열대 지방의 깊은 대류가 해들리 순환의 상승 분지를 구동해요.', example_en_3 = 'Meteorologists study deep convection to understand the formation of extreme rainfall events.', example_ko_3 = '기상학자들은 극단적인 강수 현상의 형성을 이해하기 위해 깊은 대류를 연구해요.', example_en_4 = 'Deep convection requires high moisture content and strong atmospheric instability.', example_ko_4 = '깊은 대류는 높은 수분 함량과 강한 대기 불안정이 필요해요.', example_en_5 = 'Episodes of deep convection can release enormous amounts of latent heat into the atmosphere.', example_ko_5 = '깊은 대류 에피소드는 대기 중으로 엄청난 양의 잠열을 방출할 수 있어요.' WHERE id = 'w_weather_C1_30';
UPDATE words SET example_en_2 = 'Geostrophic wind blows parallel to isobars, balancing the pressure gradient and Coriolis forces.', example_ko_2 = '지형풍은 기압 경도력과 코리올리 힘의 균형을 맞추며 등압선에 평행하게 불어요.', example_en_3 = 'The concept of geostrophic wind is fundamental to understanding large-scale atmospheric motion.', example_ko_3 = '지형풍 개념은 대규모 대기 운동을 이해하는 데 기본적이에요.', example_en_4 = 'At upper levels of the atmosphere, winds are approximately geostrophic in character.', example_ko_4 = '대기 상층에서는 바람이 대략 지형풍의 성격을 띠어요.', example_en_5 = 'Deviations from geostrophic balance drive the vertical motions that produce weather.', example_ko_5 = '지형풍 균형에서의 편차가 날씨를 만들어내는 수직 운동을 구동해요.' WHERE id = 'w_weather_C1_31';
UPDATE words SET example_en_2 = 'The Coriolis effect deflects moving air to the right in the Northern Hemisphere.', example_ko_2 = '코리올리 효과는 북반구에서 이동하는 공기를 오른쪽으로 편향시켜요.', example_en_3 = 'Without the Coriolis effect, winds would blow directly from high to low pressure.', example_ko_3 = '코리올리 효과가 없다면 바람이 고기압에서 저기압으로 직접 불 거예요.', example_en_4 = 'The Coriolis effect determines the direction of rotation of cyclones and anticyclones.', example_ko_4 = '코리올리 효과가 사이클론과 고기압의 회전 방향을 결정해요.', example_en_5 = 'The Coriolis effect is negligible at the equator and increases towards the poles.', example_ko_5 = '코리올리 효과는 적도에서는 무시할 수 있는 정도이고 극지방으로 갈수록 커져요.' WHERE id = 'w_weather_C1_32';
UPDATE words SET example_en_2 = 'Orographic lift forces moist air up a mountain slope, leading to cloud formation and rain.', example_ko_2 = '지형성 상승이 습한 공기를 산비탈 위로 밀어 올려 구름 형성과 비를 유발해요.', example_en_3 = 'The windward side of a mountain receives more rainfall due to orographic lift.', example_ko_3 = '지형성 상승 때문에 산의 바람받이쪽에 강우량이 더 많아요.', example_en_4 = 'Orographic lift is responsible for the high rainfall totals recorded on the slopes of the Himalayas.', example_ko_4 = '지형성 상승이 히말라야 사면에서 기록된 높은 강우량의 원인이에요.', example_en_5 = 'The leeward side of a mountain is typically dry because orographic lift has already wrung out the moisture.', example_ko_5 = '지형성 상승이 이미 수분을 다 빼냈기 때문에 산의 바람그늘쪽은 보통 건조해요.' WHERE id = 'w_weather_C1_33';
UPDATE words SET example_en_2 = 'An atmospheric river carried an enormous plume of moisture from the Pacific to California.', example_ko_2 = '대기천이 태평양에서 캘리포니아까지 어마어마한 수분 기둥을 운반했어요.', example_en_3 = 'Atmospheric rivers are responsible for the majority of heavy precipitation events on the US West Coast.', example_ko_3 = '대기천은 미국 서부 해안 폭우 사태의 대부분을 담당해요.', example_en_4 = 'A strong atmospheric river event can drop a year''s worth of rain in just a few days.', example_ko_4 = '강한 대기천 사태는 단 며칠 만에 1년치 강우량을 쏟아낼 수 있어요.', example_en_5 = 'The frequency and intensity of atmospheric river events are projected to increase with climate change.', example_ko_5 = '대기천 사태의 빈도와 강도가 기후 변화와 함께 증가할 것으로 예상돼요.' WHERE id = 'w_weather_C1_34';
UPDATE words SET example_en_2 = 'Climate sensitivity determines how much warming occurs for each doubling of CO₂.', example_ko_2 = '기후 민감도는 CO₂가 두 배로 늘 때마다 얼마나 온난화가 발생하는지를 결정해요.', example_en_3 = 'High climate sensitivity would mean more severe impacts at any given emissions level.', example_ko_3 = '높은 기후 민감도는 주어진 배출 수준에서 더 심각한 영향을 의미해요.', example_en_4 = 'Constraining climate sensitivity is one of the most important goals of climate science.', example_ko_4 = '기후 민감도를 제약하는 것은 기후 과학의 가장 중요한 목표 중 하나예요.', example_en_5 = 'The likely range of climate sensitivity has been narrowed but significant uncertainty remains.', example_ko_5 = '기후 민감도의 가능한 범위는 좁혀졌지만 상당한 불확실성이 남아 있어요.' WHERE id = 'w_weather_C1_35';
UPDATE words SET example_en_2 = 'Paleoclimatology uses proxy records to reconstruct climate conditions before the instrumental era.', example_ko_2 = '고기후학은 대리 기록을 사용해서 기기 시대 이전의 기후 상태를 재구성해요.', example_en_3 = 'Ice cores extracted from Antarctica provide paleoclimatological data spanning 800,000 years.', example_ko_3 = '남극에서 추출한 얼음 코어는 80만 년에 걸친 고기후학적 데이터를 제공해요.', example_en_4 = 'Paleoclimatology has revealed that today''s warming is unprecedented in at least the past 2,000 years.', example_ko_4 = '고기후학은 오늘날의 온난화가 적어도 지난 2,000년 동안 전례가 없는 것임을 밝혀냈어요.', example_en_5 = 'Sediment cores from the ocean floor are another key archive used in paleoclimatology.', example_ko_5 = '해저 퇴적물 코어는 고기후학에서 사용되는 또 다른 중요한 기록 자료예요.' WHERE id = 'w_weather_C2_01';
UPDATE words SET example_en_2 = 'The report concluded that anthropogenic greenhouse gas emissions are the dominant cause of warming.', example_ko_2 = '보고서는 인위적 온실 가스 배출이 온난화의 주요 원인이라고 결론 지었어요.', example_en_3 = 'Anthropogenic land-use change is a significant but often overlooked driver of local climate change.', example_ko_3 = '인위적 토지 이용 변화는 종종 간과되는 국지적 기후 변화의 중요한 요인이에요.', example_en_4 = 'Disentangling anthropogenic signals from natural variability requires sophisticated statistical methods.', example_ko_4 = '자연 변동성에서 인위적 신호를 분리하려면 정교한 통계 방법이 필요해요.', example_en_5 = 'Anthropogenic warming has already raised global mean temperatures by approximately 1.2 degrees Celsius.', example_ko_5 = '인위적 온난화로 이미 전 지구적 평균 기온이 약 섭씨 1.2도 상승했어요.' WHERE id = 'w_weather_C2_02';
UPDATE words SET example_en_2 = 'Biogeochemical cycles connect living organisms with the chemical and physical environment.', example_ko_2 = '생지화학적 순환은 생물 유기체를 화학적 물리적 환경과 연결해요.', example_en_3 = 'Climate change is altering biogeochemical cycles by changing decomposition rates and nutrient flows.', example_ko_3 = '기후 변화가 분해 속도와 영양분 흐름을 변화시킴으로써 생지화학적 순환을 바꾸고 있어요.', example_en_4 = 'The biogeochemical nitrogen cycle has been dramatically altered by industrial fertiliser production.', example_ko_4 = '생지화학적 질소 순환이 산업적 비료 생산에 의해 극적으로 변화했어요.', example_en_5 = 'Understanding biogeochemical feedbacks is critical for predicting Earth system responses to warming.', example_ko_5 = '생지화학적 피드백을 이해하는 것은 온난화에 대한 지구 시스템의 반응을 예측하는 데 매우 중요해요.' WHERE id = 'w_weather_C2_03';
UPDATE words SET example_en_2 = 'The teleconnection between ENSO and the Indian monsoon is one of the most studied climate linkages.', example_ko_2 = 'ENSO와 인도 몬순 사이의 원격 상관관계는 가장 많이 연구된 기후 연결 중 하나예요.', example_en_3 = 'Teleconnection patterns such as the North Atlantic Oscillation influence European winter weather.', example_ko_3 = '북대서양 진동 같은 원격 상관관계 패턴이 유럽 겨울 날씨에 영향을 미쳐요.', example_en_4 = 'Climate models must correctly simulate teleconnections to produce reliable regional forecasts.', example_ko_4 = '기후 모델은 신뢰할 수 있는 지역 예보를 만들기 위해 원격 상관관계를 정확하게 시뮬레이션해야 해요.', example_en_5 = 'Understanding teleconnections has improved seasonal forecasting skill significantly over recent decades.', example_ko_5 = '원격 상관관계를 이해함으로써 최근 수십 년간 계절 예보 기술이 크게 향상됐어요.' WHERE id = 'w_weather_C2_04';
UPDATE words SET example_en_2 = 'The thermohaline circulation drives the slow, deep flow of water across all ocean basins.', example_ko_2 = '열염 순환이 모든 해양 분지에 걸쳐 물의 느리고 깊은 흐름을 구동해요.', example_en_3 = 'Evidence suggests the thermohaline circulation has been weakening over recent decades.', example_ko_3 = '증거에 따르면 열염 순환이 최근 수십 년 동안 약화되어 왔어요.', example_en_4 = 'The thermohaline circulation takes roughly a thousand years to complete a full cycle.', example_ko_4 = '열염 순환이 전체 순환을 완료하는 데 대략 1,000년이 걸려요.', example_en_5 = 'A collapse of the thermohaline circulation would have dramatic consequences for global climate.', example_ko_5 = '열염 순환이 붕괴되면 전 지구적 기후에 극적인 결과를 초래할 거예요.' WHERE id = 'w_weather_C2_05';
UPDATE words SET example_en_2 = 'The albedo of a surface determines how much solar energy it reflects versus absorbs.', example_ko_2 = '표면의 알베도는 얼마나 많은 태양 에너지를 반사하는지 대 흡수하는지를 결정해요.', example_en_3 = 'Geoengineering proposals include increasing the albedo of urban surfaces to reduce warming.', example_ko_3 = '지구공학 제안에는 온난화를 줄이기 위해 도시 표면의 알베도를 높이는 것이 포함돼요.', example_en_4 = 'Sea ice has an albedo of around 0.5 to 0.9, far higher than open ocean water.', example_ko_4 = '해빙의 알베도는 0.5에서 0.9 정도로 열린 바다보다 훨씬 높아요.', example_en_5 = 'Changes in land-use can significantly alter local albedo and surface energy balance.', example_ko_5 = '토지 이용 변화는 지역 알베도와 지표면 에너지 균형을 크게 변화시킬 수 있어요.' WHERE id = 'w_weather_C2_06';
UPDATE words SET example_en_2 = 'A doubling of atmospheric CO₂ produces a radiative forcing of approximately 3.7 watts per square metre.', example_ko_2 = '대기 CO₂가 두 배로 증가하면 제곱미터당 약 3.7와트의 복사 강제력이 발생해요.', example_en_3 = 'Aerosol radiative forcing is one of the largest sources of uncertainty in climate projections.', example_ko_3 = '에어로졸 복사 강제력은 기후 전망에서 불확실성의 가장 큰 원천 중 하나예요.', example_en_4 = 'Reducing radiative forcing from short-lived pollutants offers a near-term climate benefit.', example_ko_4 = '단기 오염 물질의 복사 강제력을 줄이는 것은 단기적인 기후 혜택을 제공해요.', example_en_5 = 'The total anthropogenic radiative forcing since 1750 is estimated at around 2.7 watts per square metre.', example_ko_5 = '1750년 이후 총 인위적 복사 강제력은 제곱미터당 약 2.7와트로 추정돼요.' WHERE id = 'w_weather_C2_07';
UPDATE words SET example_en_2 = 'Permafrost stores vast quantities of organic carbon accumulated over thousands of years.', example_ko_2 = '영구 동토층은 수천 년에 걸쳐 축적된 방대한 양의 유기 탄소를 저장해요.', example_en_3 = 'As permafrost thaws, it releases CO₂ and methane, creating a positive climate feedback.', example_ko_3 = '영구 동토층이 해동되면서 CO₂와 메탄을 방출해서 양의 기후 피드백을 만들어요.', example_en_4 = 'The permafrost carbon feedback could significantly amplify human-caused warming.', example_ko_4 = '영구 동토층 탄소 피드백이 인간이 유발한 온난화를 크게 증폭시킬 수 있어요.', example_en_5 = 'Buildings and roads in permafrost regions are increasingly unstable as the ground softens.', example_ko_5 = '지면이 부드러워지면서 영구 동토층 지역의 건물과 도로가 점점 불안정해지고 있어요.' WHERE id = 'w_weather_C2_08';
UPDATE words SET example_en_2 = 'Dendroclimatology uses the width and density of tree rings to infer past temperatures.', example_ko_2 = '연륜기후학은 나이테의 너비와 밀도를 사용해서 과거 기온을 추론해요.', example_en_3 = 'Long-lived trees are ideal for dendroclimatology because they provide centuries of data.', example_ko_3 = '수명이 긴 나무들은 수 세기의 데이터를 제공하기 때문에 연륜기후학에 이상적이에요.', example_en_4 = 'Dendroclimatology has been used to reconstruct droughts, frosts, and volcanic eruption years.', example_ko_4 = '연륜기후학은 가뭄, 서리, 화산 폭발 연도를 재구성하는 데 사용됐어요.', example_en_5 = 'The combination of dendroclimatology and ice-core records strengthens confidence in past climate reconstructions.', example_ko_5 = '연륜기후학과 얼음 코어 기록의 조합이 과거 기후 재구성에 대한 신뢰도를 높여요.' WHERE id = 'w_weather_C2_09';
UPDATE words SET example_en_2 = 'Ice cores serve as a climate proxy by preserving ancient air bubbles within the ice.', example_ko_2 = '얼음 코어는 얼음 안에 고대 공기 방울을 보존함으로써 기후 대리 지표 역할을 해요.', example_en_3 = 'Pollen preserved in lake sediments is a key proxy for reconstructing past vegetation and climate.', example_ko_3 = '호수 퇴적물에 보존된 꽃가루는 과거 식생과 기후를 재구성하는 핵심 대리 지표예요.', example_en_4 = 'Proxy records are essential for extending the climate record beyond the instrumental period.', example_ko_4 = '대리 기록은 기후 기록을 기기 시대 이전으로 확장하는 데 필수적이에요.', example_en_5 = 'Coral proxy records provide high-resolution data on tropical sea surface temperatures.', example_ko_5 = '산호 대리 기록은 열대 해수면 온도에 대한 고해상도 데이터를 제공해요.' WHERE id = 'w_weather_C2_10';
UPDATE words SET example_en_2 = 'Changes in insolation driven by orbital cycles have triggered past ice ages.', example_ko_2 = '궤도 주기에 의해 유발된 일사량 변화가 과거 빙하기를 촉발했어요.', example_en_3 = 'Insolation at the top of the atmosphere varies with latitude, season, and Earth''s orbital parameters.', example_ko_3 = '대기권 상단의 일사량은 위도, 계절, 지구의 궤도 매개변수에 따라 변해요.', example_en_4 = 'Higher insolation in summer melts ice and warms the surface more effectively than solar output alone.', example_ko_4 = '여름의 높은 일사량이 태양 출력만으로보다 더 효과적으로 얼음을 녹이고 표면을 따뜻하게 해요.', example_en_5 = 'The spatial distribution of insolation is a key driver of global atmospheric and ocean circulation.', example_ko_5 = '일사량의 공간적 분포는 전 지구적 대기 및 해양 순환의 핵심 요인이에요.' WHERE id = 'w_weather_C2_11';
UPDATE words SET example_en_2 = 'Milankovitch cycles describe periodic variations in Earth''s orbit and axial tilt.', example_ko_2 = '밀란코비치 주기는 지구의 궤도와 자전축 기울기의 주기적 변화를 설명해요.', example_en_3 = 'Milankovitch cycles operate on timescales of tens to hundreds of thousands of years.', example_ko_3 = '밀란코비치 주기는 수만에서 수십만 년의 시간 규모로 작동해요.', example_en_4 = 'The timing of glacial and interglacial periods correlates closely with Milankovitch cycles.', example_ko_4 = '빙하기와 간빙기의 시기는 밀란코비치 주기와 밀접하게 상관관계가 있어요.', example_en_5 = 'Understanding Milankovitch cycles helps scientists place current climate change in a geological context.', example_ko_5 = '밀란코비치 주기를 이해하면 과학자들이 현재 기후 변화를 지질학적 맥락에서 파악하는 데 도움이 돼요.' WHERE id = 'w_weather_C2_12';
UPDATE words SET example_en_2 = 'The cryosphere includes all frozen water on Earth, from ice sheets to mountain glaciers.', example_ko_2 = '빙권에는 빙상에서 산악 빙하까지 지구의 모든 얼어붙은 물이 포함돼요.', example_en_3 = 'Changes in the cryosphere are among the most visible indicators of climate change.', example_ko_3 = '빙권의 변화는 기후 변화의 가장 눈에 띄는 지표 중 하나예요.', example_en_4 = 'Significant cryosphere loss could raise global sea levels by several metres over coming centuries.', example_ko_4 = '빙권이 크게 감소하면 앞으로 수 세기에 걸쳐 전 지구적 해수면이 수 미터 상승할 수 있어요.', example_en_5 = 'The cryosphere plays a crucial role in regulating Earth''s energy balance through its high albedo.', example_ko_5 = '빙권은 높은 알베도를 통해 지구의 에너지 균형을 조절하는 데 중요한 역할을 해요.' WHERE id = 'w_weather_C2_13';
UPDATE words SET example_en_2 = 'The hydrological cycle links precipitation, evaporation, runoff, and groundwater recharge.', example_ko_2 = '수문 순환은 강수, 증발, 유출, 지하수 충전을 연결해요.', example_en_3 = 'Climate change is intensifying the hydrological cycle, making wet areas wetter and dry areas drier.', example_ko_3 = '기후 변화가 수문 순환을 강화하여 습한 지역은 더 습하게, 건조한 지역은 더 건조하게 만들고 있어요.', example_en_4 = 'Human water use accounts for a significant fraction of the total land surface hydrological cycle.', example_ko_4 = '인간의 물 사용이 전체 육지 표면 수문 순환의 상당 부분을 차지해요.', example_en_5 = 'The hydrological cycle regulates freshwater availability and is fundamental to all life on Earth.', example_ko_5 = '수문 순환은 담수 가용성을 조절하고 지구의 모든 생명에 근본적으로 중요해요.' WHERE id = 'w_weather_C2_14';
UPDATE words SET example_en_2 = 'Sudden stratospheric warming events can disrupt the polar vortex and bring cold air equatorward.', example_ko_2 = '갑작스러운 성층권 온난화 사태가 극소용돌이를 교란시켜 적도 쪽으로 차가운 공기를 가져올 수 있어요.', example_en_3 = 'Stratospheric warming events in winter can precede extreme cold snaps at the surface by several weeks.', example_ko_3 = '겨울의 성층권 온난화 사태는 지표면의 극한 한파에 몇 주 앞서 발생할 수 있어요.', example_en_4 = 'Climate change may increase the frequency of stratospheric warming events through jet stream modification.', example_ko_4 = '기후 변화가 제트 기류 수정을 통해 성층권 온난화 사태의 빈도를 높일 수 있어요.', example_en_5 = 'Stratospheric warming signals can serve as precursors to surface weather extremes weeks in advance.', example_ko_5 = '성층권 온난화 신호는 몇 주 전에 지표면 기상 극단의 전조 역할을 할 수 있어요.' WHERE id = 'w_weather_C2_15';
UPDATE words SET example_en_2 = 'Forests and soils are major carbon sinks, performing vital carbon sequestration services.', example_ko_2 = '숲과 토양은 중요한 탄소 격리 서비스를 제공하는 주요 탄소 흡수원이에요.', example_en_3 = 'Carbon sequestration in the ocean occurs mainly through the biological and solubility pumps.', example_ko_3 = '해양의 탄소 격리는 주로 생물학적 및 용해도 펌프를 통해 이루어져요.', example_en_4 = 'Direct air capture is an emerging technology for artificial carbon sequestration.', example_ko_4 = '직접 공기 포집은 인공 탄소 격리를 위한 신흥 기술이에요.', example_en_5 = 'Enhanced carbon sequestration in agricultural soils could make a meaningful contribution to climate goals.', example_ko_5 = '농업 토양의 강화된 탄소 격리가 기후 목표에 의미 있는 기여를 할 수 있어요.' WHERE id = 'w_weather_C2_16';
UPDATE words SET example_en_2 = 'The cloud albedo effect refers to how additional cloud cover increases Earth''s reflectivity.', example_ko_2 = '구름 알베도 효과는 구름 덮개가 증가할수록 지구의 반사율이 높아지는 것을 말해요.', example_en_3 = 'Aerosol pollution can enhance the cloud albedo effect by providing additional cloud condensation nuclei.', example_ko_3 = '에어로졸 오염이 추가적인 구름 응결핵을 제공함으로써 구름 알베도 효과를 강화할 수 있어요.', example_en_4 = 'The cloud albedo effect represents one of the most uncertain feedbacks in climate science.', example_ko_4 = '구름 알베도 효과는 기후 과학에서 가장 불확실한 피드백 중 하나예요.', example_en_5 = 'Proposed geoengineering approaches include artificially enhancing the cloud albedo effect to cool the planet.', example_ko_5 = '제안된 지구공학 접근법에는 지구를 냉각하기 위해 인위적으로 구름 알베도 효과를 강화하는 것이 포함돼요.' WHERE id = 'w_weather_C2_17';
UPDATE words SET example_en_2 = 'Isotope analysis of ice cores reveals past atmospheric composition and temperatures.', example_ko_2 = '얼음 코어의 동위원소 분석이 과거 대기 성분과 기온을 드러내요.', example_en_3 = 'The isotope analysis of coral skeletons provides a record of ocean temperature over centuries.', example_ko_3 = '산호 골격의 동위원소 분석이 수 세기에 걸친 해양 온도 기록을 제공해요.', example_en_4 = 'Oxygen isotope analysis is widely used to determine paleotemperatures from deep-sea sediments.', example_ko_4 = '산소 동위원소 분석은 심해 퇴적물에서 고기온을 결정하기 위해 널리 사용돼요.', example_en_5 = 'Advances in isotope analysis have greatly improved the resolution of climate reconstructions.', example_ko_5 = '동위원소 분석의 발전이 기후 재구성의 해상도를 크게 향상시켰어요.' WHERE id = 'w_weather_C2_18';
UPDATE words SET example_en_2 = 'Forests are the dominant natural source of biogenic volatile organic compounds globally.', example_ko_2 = '숲은 전 세계적으로 생물 기원 휘발성 유기 화합물의 주요 자연 공급원이에요.', example_en_3 = 'Biogenic volatile organic compounds react with pollutants to form secondary aerosols.', example_ko_3 = '생물 기원 휘발성 유기 화합물은 오염 물질과 반응하여 이차 에어로졸을 형성해요.', example_en_4 = 'Emissions of biogenic volatile organic compounds increase substantially under higher temperatures.', example_ko_4 = '생물 기원 휘발성 유기 화합물의 배출이 고온에서 크게 증가해요.', example_en_5 = 'The interaction between biogenic volatile organic compounds and anthropogenic pollutants contributes to tropospheric ozone formation.', example_ko_5 = '생물 기원 휘발성 유기 화합물과 인위적 오염 물질 간의 상호작용이 대류권 오존 형성에 기여해요.' WHERE id = 'w_weather_C2_19';
UPDATE words SET example_en_2 = 'The geological record contains evidence of abrupt climate change events within years to decades.', example_ko_2 = '지질 기록에는 수년에서 수십 년 내에 발생한 급격한 기후 변화 사태의 증거가 있어요.', example_en_3 = 'Abrupt climate change poses special challenges for adaptation because of its rapid onset.', example_ko_3 = '급격한 기후 변화는 빠른 발생 때문에 적응에 특별한 어려움을 초래해요.', example_en_4 = 'The Younger Dryas is a well-documented example of abrupt climate change from the paleorecord.', example_ko_4 = '영거 드라이아스는 고기후 기록에서 잘 문서화된 급격한 기후 변화의 사례예요.', example_en_5 = 'Some scientists warn that current forcing trajectories increase the risk of abrupt climate change.', example_ko_5 = '일부 과학자들은 현재 강제력 궤도가 급격한 기후 변화의 위험을 높인다고 경고해요.' WHERE id = 'w_weather_C2_20';
UPDATE words SET example_en_2 = 'Solar irradiance varies slightly over the eleven-year sunspot cycle.', example_ko_2 = '태양 복사 조도는 11년 흑점 주기에 걸쳐 약간 변화해요.', example_en_3 = 'Total solar irradiance is monitored continuously by satellites to detect long-term trends.', example_ko_3 = '전체 태양 복사 조도는 장기 추세를 감지하기 위해 위성으로 지속적으로 모니터링돼요.', example_en_4 = 'Changes in solar irradiance cannot explain the warming trend observed since the mid-20th century.', example_ko_4 = '태양 복사 조도의 변화는 20세기 중반 이후 관측된 온난화 추세를 설명할 수 없어요.', example_en_5 = 'Accurate satellite measurements of solar irradiance began in 1978 and continue to the present day.', example_ko_5 = '태양 복사 조도의 정확한 위성 측정이 1978년에 시작되어 현재까지 계속되고 있어요.' WHERE id = 'w_weather_C2_21';
UPDATE words SET example_en_2 = 'The water vapour feedback mechanism amplifies initial warming caused by greenhouse gases.', example_ko_2 = '수증기 피드백 메커니즘이 온실 가스에 의한 초기 온난화를 증폭시켜요.', example_en_3 = 'A negative feedback mechanism in the climate system tends to resist change and restore equilibrium.', example_ko_3 = '기후 시스템의 음의 피드백 메커니즘은 변화에 저항하고 평형을 회복하는 경향이 있어요.', example_en_4 = 'Understanding feedback mechanisms is central to estimating climate sensitivity accurately.', example_ko_4 = '피드백 메커니즘을 이해하는 것은 기후 민감도를 정확하게 추정하는 데 핵심이에요.', example_en_5 = 'Multiple interacting feedback mechanisms make the Earth''s climate response to forcing highly complex.', example_ko_5 = '상호 작용하는 여러 피드백 메커니즘이 강제력에 대한 지구 기후 반응을 매우 복잡하게 만들어요.' WHERE id = 'w_weather_C2_22';
UPDATE words SET example_en_2 = 'Tracking global mean surface temperature requires data from thousands of ocean buoys and land stations.', example_ko_2 = '전 지구 평균 지표면 온도를 추적하려면 수천 개의 해양 부이와 육지 관측소의 데이터가 필요해요.', example_en_3 = 'The global mean surface temperature in 2023 was the highest ever recorded.', example_ko_3 = '2023년 전 지구 평균 지표면 온도가 역사상 가장 높았어요.', example_en_4 = 'Small changes in global mean surface temperature can translate into large regional climate impacts.', example_ko_4 = '전 지구 평균 지표면 온도의 작은 변화가 큰 지역적 기후 영향으로 이어질 수 있어요.', example_en_5 = 'Blending satellite and in-situ measurements improves the accuracy of global mean surface temperature estimates.', example_ko_5 = '위성과 현장 측정을 결합하면 전 지구 평균 지표면 온도 추정치의 정확도가 향상돼요.' WHERE id = 'w_weather_C2_23';
UPDATE words SET example_en_2 = 'Methane is a potent forcing agent with a global warming potential about 80 times that of CO₂.', example_ko_2 = '메탄은 CO₂보다 약 80배의 지구 온난화 잠재력을 가진 강력한 강제력 요인이에요.', example_en_3 = 'Black carbon is a short-lived forcing agent that can be reduced through cleaner combustion practices.', example_ko_3 = '블랙 카본은 더 깨끗한 연소 관행을 통해 줄일 수 있는 단기 강제력 요인이에요.', example_en_4 = 'Identifying the contribution of each forcing agent helps prioritise mitigation efforts.', example_ko_4 = '각 강제력 요인의 기여를 확인하면 완화 노력을 우선순위화하는 데 도움이 돼요.', example_en_5 = 'Natural forcing agents such as volcanic aerosols can temporarily offset anthropogenic warming.', example_ko_5 = '화산 에어로졸과 같은 자연적 강제력 요인이 인위적 온난화를 일시적으로 상쇄할 수 있어요.' WHERE id = 'w_weather_C2_24';
UPDATE words SET example_en_2 = 'Sea ice extent in the Arctic set a record minimum in September 2023.', example_ko_2 = '북극의 해빙 면적이 2023년 9월에 최소 기록을 경신했어요.', example_en_3 = 'Sea ice extent in Antarctica has shown surprising year-to-year variability in recent observations.', example_ko_3 = '남극의 해빙 면적이 최근 관측에서 놀라운 연간 변동성을 보이고 있어요.', example_en_4 = 'The shrinking sea ice extent in the Arctic is opening new shipping routes.', example_ko_4 = '북극의 해빙 면적 감소가 새로운 항로를 열고 있어요.', example_en_5 = 'Reduced sea ice extent amplifies Arctic warming through the ice-albedo feedback.', example_ko_5 = '감소된 해빙 면적이 얼음-알베도 피드백을 통해 북극 온난화를 증폭시켜요.' WHERE id = 'w_weather_C2_25';
UPDATE words SET example_en_2 = 'The last ice age peaked around 20,000 years ago, when ice sheets covered much of North America.', example_ko_2 = '마지막 빙하기는 약 2만 년 전에 절정을 이루었을 때 빙상이 북아메리카 상당 부분을 덮었어요.', example_en_3 = 'Ice age cycles are paced by Milankovitch orbital variations and amplified by internal feedbacks.', example_ko_3 = '빙하기 주기는 밀란코비치 궤도 변화에 의해 조율되고 내부 피드백에 의해 증폭돼요.', example_en_4 = 'Evidence from the last ice age shows that global temperatures can shift by several degrees in just centuries.', example_ko_4 = '마지막 빙하기의 증거는 전 지구 기온이 불과 수 세기 만에 몇 도씩 변할 수 있음을 보여줘요.', example_en_5 = 'The transition out of the last ice age provides a natural analogue for understanding rapid climate change.', example_ko_5 = '마지막 빙하기에서 벗어나는 전환이 급격한 기후 변화를 이해하기 위한 자연적 유사체를 제공해요.' WHERE id = 'w_weather_C2_26';
UPDATE words SET example_en_2 = 'Water vapour feedback roughly doubles the warming effect of CO₂ alone.', example_ko_2 = '수증기 피드백이 CO₂만의 온난화 효과를 대략 두 배로 만들어요.', example_en_3 = 'The water vapour feedback operates on a timescale of days, making it a fast feedback.', example_ko_3 = '수증기 피드백은 며칠의 시간 규모로 작동하여 빠른 피드백이에요.', example_en_4 = 'Understanding the water vapour feedback is essential for accurate climate sensitivity estimates.', example_ko_4 = '수증기 피드백을 이해하는 것은 정확한 기후 민감도 추정에 필수적이에요.', example_en_5 = 'The water vapour feedback is considered one of the most robust and well-understood climate feedbacks.', example_ko_5 = '수증기 피드백은 가장 강건하고 잘 이해된 기후 피드백 중 하나로 여겨져요.' WHERE id = 'w_weather_C2_27';
UPDATE words SET example_en_2 = 'Palaeotemperature reconstructions from ice cores span the last 800,000 years.', example_ko_2 = '얼음 코어의 고기온 재구성은 지난 80만 년에 걸쳐 있어요.', example_en_3 = 'Comparing palaeotemperature records with CO₂ levels reveals a strong historical correlation.', example_ko_3 = '고기온 기록과 CO₂ 수준을 비교하면 강한 역사적 상관관계가 드러나요.', example_en_4 = 'Palaeotemperature estimates carry uncertainties that must be carefully quantified.', example_ko_4 = '고기온 추정치에는 신중하게 정량화해야 하는 불확실성이 있어요.', example_en_5 = 'Palaeotemperature data from tropical regions is needed to constrain global climate sensitivity better.', example_ko_5 = '전 지구적 기후 민감도를 더 잘 제약하기 위해 열대 지역의 고기온 데이터가 필요해요.' WHERE id = 'w_weather_C2_28';
UPDATE words SET example_en_2 = 'Heterogeneous nucleation of ice crystals occurs on aerosol particles called ice nuclei.', example_ko_2 = '얼음 결정의 불균일 핵 생성은 얼음 핵이라고 불리는 에어로졸 입자에서 발생해요.', example_en_3 = 'Heterogeneous nucleation requires lower supersaturation than homogeneous nucleation.', example_ko_3 = '불균일 핵 생성은 균일 핵 생성보다 낮은 과포화를 필요로 해요.', example_en_4 = 'Biological particles such as pollen and bacteria can serve as efficient ice nuclei for heterogeneous nucleation.', example_ko_4 = '꽃가루와 박테리아 같은 생물학적 입자들이 불균일 핵 생성을 위한 효율적인 얼음 핵 역할을 할 수 있어요.', example_en_5 = 'The efficiency of heterogeneous nucleation influences the microphysics of clouds and precipitation.', example_ko_5 = '불균일 핵 생성의 효율성이 구름과 강수의 미세물리학에 영향을 미쳐요.' WHERE id = 'w_weather_C2_29';
UPDATE words SET example_en_2 = 'Integrated assessment models are used to evaluate the cost-effectiveness of different climate policies.', example_ko_2 = '통합 평가 모델은 다양한 기후 정책의 비용 효율성을 평가하는 데 사용돼요.', example_en_3 = 'Integrated assessment models couple economic and climate system components to assess mitigation pathways.', example_ko_3 = '통합 평가 모델은 경제 및 기후 시스템 구성 요소를 결합하여 완화 경로를 평가해요.', example_en_4 = 'Critics argue that integrated assessment models may underrepresent tail risks and catastrophic outcomes.', example_ko_4 = '비평가들은 통합 평가 모델이 꼬리 위험과 대재앙적 결과를 과소 반영할 수 있다고 주장해요.', example_en_5 = 'Integrated assessment models played a central role in developing the scenarios used by the IPCC.', example_ko_5 = '통합 평가 모델이 IPCC가 사용하는 시나리오를 개발하는 데 중심적인 역할을 했어요.' WHERE id = 'w_weather_C2_30';
UPDATE words SET example_en_2 = 'Countries that have ratified the Paris Agreement are expected to align with a carbon budget consistent with 1.5 degrees.', example_ko_2 = '파리 협정을 비준한 국가들은 1.5도에 부합하는 탄소 예산에 맞추도록 기대돼요.', example_en_3 = 'The global carbon budget for 1.5 degrees of warming has already been largely spent.', example_ko_3 = '1.5도 온난화를 위한 전 지구적 탄소 예산이 이미 대부분 소진됐어요.', example_en_4 = 'Distributing the remaining carbon budget fairly across nations raises profound ethical questions.', example_ko_4 = '나머지 탄소 예산을 국가들 사이에 공정하게 배분하는 것은 심오한 윤리적 질문을 제기해요.', example_en_5 = 'Regular carbon budget assessments track whether global emissions are consistent with agreed temperature targets.', example_ko_5 = '정기적인 탄소 예산 평가가 전 지구적 배출량이 합의된 온도 목표와 일치하는지 추적해요.' WHERE id = 'w_weather_C2_31';
UPDATE words SET example_en_2 = 'Current emission pathways suggest warming well above two degrees by the end of the century.', example_ko_2 = '현재 배출 경로는 이번 세기 말까지 2도를 훨씬 초과하는 온난화를 시사해요.', example_en_3 = 'Ambitious emission pathways require deep decarbonisation of energy, transport, and industry.', example_ko_3 = '야심찬 배출 경로는 에너지, 운송, 산업의 심층 탈탄소화를 필요로 해요.', example_en_4 = 'The IPCC assessed multiple emission pathways ranging from very high to very low future emissions.', example_ko_4 = 'IPCC는 매우 높은 배출에서 매우 낮은 미래 배출까지 다양한 배출 경로를 평가했어요.', example_en_5 = 'Choosing an emission pathway is ultimately a political decision with profound intergenerational implications.', example_ko_5 = '배출 경로를 선택하는 것은 궁극적으로 심오한 세대 간 함의를 가진 정치적 결정이에요.' WHERE id = 'w_weather_C2_32';
UPDATE words SET example_en_2 = 'Achieving net zero by mid-century requires not only cutting emissions but also removing CO₂ from the atmosphere.', example_ko_2 = '21세기 중반까지 탄소 중립을 달성하려면 배출량 감축뿐만 아니라 대기에서 CO₂를 제거해야 해요.', example_en_3 = 'Companies are under increasing pressure to set credible net zero targets backed by science.', example_ko_3 = '기업들은 과학에 뒷받침된 신뢰할 수 있는 탄소 중립 목표를 설정하라는 압력을 받고 있어요.', example_en_4 = 'Reaching net zero requires contributions from every sector of the economy.', example_ko_4 = '탄소 중립에 도달하려면 경제의 모든 부문에서 기여가 필요해요.', example_en_5 = 'The concept of net zero accounts for both emissions produced and emissions removed from the atmosphere.', example_ko_5 = '탄소 중립 개념은 생산된 배출량과 대기에서 제거된 배출량 모두를 고려해요.' WHERE id = 'w_weather_C2_33';
UPDATE words SET example_en_2 = 'Tectonic influence on climate operated over millions of years as continents drifted and mountain ranges formed.', example_ko_2 = '대륙이 이동하고 산맥이 형성되면서 기후에 대한 지각 영향이 수백만 년에 걸쳐 작용했어요.', example_en_3 = 'The uplift of the Himalayas is believed to have intensified the Asian monsoon through tectonic influence.', example_ko_3 = '히말라야의 융기가 지각 영향을 통해 아시아 몬순을 강화했다고 여겨져요.', example_en_4 = 'Tectonic influence on atmospheric CO₂ operates through volcanic degassing and rock weathering.', example_ko_4 = '대기 CO₂에 대한 지각 영향은 화산 탈가스와 암석 풍화를 통해 작동해요.', example_en_5 = 'Distinguishing tectonic influence on climate from other long-term forcing factors is methodologically challenging.', example_ko_5 = '기후에 대한 지각 영향을 다른 장기 강제력 요인과 구분하는 것은 방법론적으로 어려워요.' WHERE id = 'w_weather_C2_34';
UPDATE words SET example_en_2 = 'Deep time climate reconstructions reveal ice-free poles and much warmer global average temperatures millions of years ago.', example_ko_2 = '심층 시간 기후 재구성이 수백만 년 전 얼음 없는 극지방과 훨씬 더 따뜻한 전 지구적 평균 기온을 드러내요.', example_en_3 = 'Understanding deep time climate helps contextualise the pace and magnitude of current anthropogenic change.', example_ko_3 = '심층 시간 기후를 이해하면 현재 인위적 변화의 속도와 규모를 맥락화하는 데 도움이 돼요.', example_en_4 = 'Deep time climate states such as the Eocene Optimum offer potential analogues for future warming scenarios.', example_ko_4 = '에오세 최적기 같은 심층 시간 기후 상태가 미래 온난화 시나리오에 대한 잠재적 유사체를 제공해요.', example_en_5 = 'The deep time climate record extends the context for understanding Earth system sensitivity beyond recent glacial cycles.', example_ko_5 = '심층 시간 기후 기록이 지구 시스템 민감도를 이해하기 위한 맥락을 최근 빙하 주기 너머로 확장해요.' WHERE id = 'w_weather_C2_35';
